content:
组件化架构是现代游戏开发的核心设计模式之一。本章将介绍如何在 Godot C# 中构建灵活的组件系统，包括传统组件模式、轻量级 ECS 架构以及依赖注入容器的实现。
1. 设计原理与思路 1.1 组合优于继承的设计哲学 传统的面向对象编程倾向于使用继承来复用代码，但在游戏开发中，继承往往会导致以下问题：
继承的困境：
// 继承导致的类爆炸 public class Character : Node { } public class Player : Character { } // 玩家可以飞行 public class FlyingPlayer : Player { } // 玩家可以隐身 public class InvisiblePlayer : Player { } // 玩家既可以飞行又可以隐身？ // public class FlyingInvisiblePlayer : ??? // 多重继承问题 组合的解决方案：
// 组件化设计 public class Player : Node { // 通过组合实现功能 public MovementComponent Movement { get; private set; } public HealthComponent Health { get; private set; } public override void _Ready() { Movement = AddComponent&lt;MovementComponent&gt;(); Health = AddComponent&lt;HealthComponent&gt;(); // 动态添加能力 if (CanFly) AddComponent&lt;FlyingComponent&gt;(); if (CanBecomeInvisible) AddComponent&lt;InvisibilityComponent&gt;(); } } 组合的优势：
继承 vs 组合： 继承（Is-A关系）： Character │ ┌─────────────┼─────────────┐ │ │ │ Player Enemy NPC │ ┌────┴────┐ │ │ FlyingPlayer InvisiblePlayer │ │ 问题：无法同时拥有飞行和隐身 ▼ FlyingInvisiblePlayer 组合（Has-A关系）： Entity │ ├── MovementComponent ├── HealthComponent ├── FlyingComponent (可选) ├── InvisibilityComponent (可选) └── WeaponComponent (可选) 优势：可以自由组合任意功能 1.2 ECS架构的演进 ECS（Entity-Component-System）架构经历了三个主要阶段：
第一代：面向对象的组件模式（OOP Components）
组件是行为容器 组件可以包含逻辑 典型的代表：Unity的MonoBehaviour 第二代：数据驱动的组件模式（Data-Oriented Components）
组件是纯数据结构 逻辑由System处理 更好的缓存友好性 第三代：ECS（Entity-Component-System）
实体只是ID 组件是数据 系统是逻辑处理器 扁平化的内存布局 内存布局对比： 面向对象（OOP）： [Entity1: Transform, Health, Renderer] [Entity2: Transform, Health] [Entity3: Renderer] 问题：内存分散，缓存未命中率高 ECS（Data-Oriented）： Transforms: [T1][T2][T3][T4]... Healths: [H1][H2][H3][H4]... Renderers: [R1][R2][R3][R4]... 优势：连续内存访问，CPU缓存友好 为什么这样设计？
缓存友好：连续存储相同类型的数据，提高CPU缓存命中率 并行友好：System可以并行处理大量实体 查询高效：可以快速筛选拥有特定组件组合的实体 1.3 组件化与Godot节点系统的结合 Godot的节点系统本质上就是组件化架构。我们的组件系统建立在Godot节点系统之上：
架构层次： Level 1 - Godot引擎： ├─ Node ├─ Node2D ├─ Node3D └─ Control Level 2 - 框架组件层： ├─ ComponentBase : Node ├─ GameEntity : ComponentBase └─ UIComponent : Control Level 3 - 业务组件层： ├─ HealthComponent : ComponentBase ├─ MovementComponent : ComponentBase ├─ WeaponComponent : ComponentBase └─ InventoryComponent : ComponentBase Level 4 - 具体游戏逻辑： ├─ PlayerHealth : HealthComponent ├─ EnemyAI : AIComponent └─ BossAttack : AttackComponent 这种设计的好处：
保留Godot编辑器的可视化编辑能力 利用Godot的信号系统 与Godot的生命周期（_Ready, _Process等）无缝集成 2. 使用场景分析 2.1 适用场景 复杂实体：角色需要同时具备多种能力
// RPG角色系统 public class RPGCharacter : GameEntity { protected override void SetupComponents() { AddComponent&lt;HealthComponent&gt;(new HealthComponent { MaxHealth = 100, HealthRegenRate = 1.0f }); AddComponent&lt;MovementComponent&gt;(new MovementComponent { MoveSpeed = 5.0f, CanSprint = true }); AddComponent&lt;CombatComponent&gt;(new CombatComponent { AttackDamage = 10, AttackSpeed = 1.0f }); AddComponent&lt;InventoryComponent&gt;(new InventoryComponent { MaxSlots = 20 }); AddComponent&lt;EquipmentComponent&gt;(); // 装备系统 AddComponent&lt;SkillComponent&gt;(); // 技能系统 } } 可复用功能：多个实体共享相同的行为
// 多个实体都可以拥有生命值 public class Player : GameEntity { } public class Enemy : GameEntity { } public class DestructibleObject : GameEntity { } // 所有都可以添加HealthComponent player.AddComponent&lt;HealthComponent&gt;(); enemy.AddComponent&lt;HealthComponent&gt;(); object.AddComponent&lt;HealthComponent&gt;(); 2.2 不适用场景 简单对象：只有一个功能的简单对象
// 不需要组件化 public class SimpleBullet : Node2D { [Export] public float Speed { get; set; } = 500f; [Export] public int Damage { get; set; } = 10; public override void _PhysicsProcess(double delta) { Position += Transform.X * Speed * (float)delta; } } // 对比：组件化（过度设计） public class BulletEntity : GameEntity { protected override void SetupComponents() { AddComponent&lt;MovementComponent&gt;(); AddComponent&lt;DamageComponent&gt;(); // 太多样板代码 } } 紧密耦合的逻辑：逻辑高度依赖，无法拆分的功能
2.3 典型案例 RPG角色系统：生命、魔法、经验、装备、技能等模块独立 装备系统：武器、护甲、饰品可以任意组合 Buff/Debuff系统：通过添加/移除组件实现临时效果
装备系统组件图： 角色实体： ├─ HealthComponent ├─ ManaComponent ├─ MovementComponent ├─ CombatComponent ├─ InventoryComponent │ ├─ Slot0: Sword (WeaponComponent) │ ├─ Slot1: Shield (ArmorComponent) │ └─ Slot2: Potion (ConsumableComponent) ├─ EquipmentComponent │ ├─ Weapon: Sword │ ├─ Armor: PlateMail │ └─ Ring: RingOfHealth └─ BuffComponent ├─ SpeedBuff (持续时间30秒) └─ StrengthBuff (持续时间60秒) 优势：装备更换只需替换组件引用 3. 实现细节讲解 3.1 依赖注入容器的工作原理 依赖注入容器管理对象的创建和依赖关系：
DI容器工作流程： 1. 注册阶段（Register）： container.Register&lt;IService, ServiceImpl&gt;(ServiceLifetime.Singleton); 2. 解析阶段（Resolve）： var service = container.Resolve&lt;IService&gt;(); 3. 创建实例（Create Instance）： ├─ 检查构造函数 ├─ 解析参数依赖 ├─ 创建实例 ├─ 属性注入 └─ 调用[Initialize]方法 4. 生命周期管理： Singleton: 全局唯一实例 Scoped: 作用域内共享 Transient: 每次新建实例 构造函数注入的实现：
private object CreateInstance(Type implementationType) { // 1. 获取构造函数 var constructor = implementationType.GetConstructors() .OrderByDescending(c =&gt; c.GetParameters().Length) .First(); var parameters = constructor.GetParameters(); var args = new object[parameters.Length]; // 2. 解析每个参数 for (int i = 0; i &lt; parameters.Length; i++) { var param = parameters[i]; // 递归解析依赖 args[i] = Resolve(param.ParameterType); } // 3. 创建实例 var instance = constructor.Invoke(args); // 4. 执行属性注入 InjectProperties(instance); return instance; } // 为什么这样设计？ // 递归解析确保所有依赖都被满足 // 支持嵌套依赖（A依赖B，B依赖C） 3.2 组件生命周期管理 组件的生命周期与Godot节点生命周期结合：
public abstract class ComponentBase : Node { // Godot生命周期 public override void _Ready() { base._Ready(); Initialize(); // 调用框架初始化 } public override void _Process(double delta) { if (_isEnabled &amp;&amp; _isInitialized) { OnUpdate((float)delta); } } public override void _ExitTree() { OnDestroy(); base._ExitTree(); } // 框架生命周期 protected virtual void Initialize() { if (_isInitialized) return; OnInitialize(); // 子类实现 _isInitialized = true; } protected abstract void OnInitialize(); protected virtual void OnUpdate(float deltaTime) { } protected virtual void OnDestroy() { } } 生命周期执行顺序：
1. _Ready() [Godot] └─ Initialize() [框架] └─ OnInitialize() [子类] 2. _Process() [Godot] - 每帧 └─ OnUpdate() [子类] - 如果启用 3. _ExitTree() [Godot] └─ OnDestroy() [子类] 注意：OnInitialize在_Godot的_Ready之后执行，确保节点树已准备好 3.3 与Godot原生组件的协作 我们的组件系统与Godot原生节点和组件协作：
public class HealthComponent : ComponentBase { // 引用Godot原生节点 private ProgressBar _healthBar; private AnimationPlayer _animator; protected override void OnInitialize() { // 在节点树中查找Godot节点 _healthBar = GetNode&lt;ProgressBar&gt;(&#34;UI/HealthBar&#34;); _animator = GetNode&lt;AnimationPlayer&gt;(&#34;AnimationPlayer&#34;); // 连接Godot信号 _healthBar.ValueChanged += OnHealthBarValueChanged; } // 与Godot信号集成 [Signal] public delegate void HealthDepletedEventHandler(); public void TakeDamage(int damage) { CurrentHealth -= damage; // 触发Godot信号 EmitSignal(SignalName.HealthDepleted); // 播放Godot动画 _animator?.Play(&#34;hit&#34;); } } // 组合使用示例 public class Player : CharacterBody2D // Godot原生 { private HealthComponent _health; // 框架组件 public override void _Ready() { // 添加框架组件 _health = new HealthComponent(); AddChild(_health); // 连接框架组件信号 _health.HealthDepleted += OnHealthDepleted; } private void OnHealthDepleted() { // 使用Godot功能 GetTree().ReloadCurrentScene(); } } 为什么这样设计？
利用Godot的场景系统和可视化编辑器 保留Godot信号系统的便利性 渐进式采用框架组件，不完全替换Godot功能 4. 性能与权衡 4.1 组件查找的开销 组件查找主要有两种方式，各有优劣：
方式一：字典查找（O(1)）
// Entity中使用字典存储组件 private Dictionary&lt;Type, IComponent&gt; _components = new(); public T GetComponent&lt;T&gt;() where T : class, IComponent { if (_components.TryGetValue(typeof(T), out var component)) return component as T; return null; } // 时间复杂度：O(1) // 内存开销：每个组件类型一个字典项 方式二：线性查找（O(n)）
// Godot的GetNode方式 public T GetComponent&lt;T&gt;() { foreach (Node child in GetChildren()) { if (child is T component) return component; } return null; } // 时间复杂度：O(n)，n为子节点数量 // 内存开销：无额外开销 性能对比：
查找方式 时间复杂度 内存开销 适用场景 字典查找 O(1) 中等 频繁查找 线性查找 O(n) 低 不频繁查找 缓存引用 O(1) 高 最高频访问 优化策略：
// 缓存高频访问的组件 public class Player : GameEntity { private HealthComponent _health; // 缓存 protected override void OnInitialize() { _health = GetComponent&lt;HealthComponent&gt;(); // 初始化时缓存 } public void TakeDamage(int damage) { _health.TakeDamage(damage); // 直接使用缓存，O(1) } } 4.2 内存布局优化 ECS架构的核心优势之一是内存布局优化：
传统OOP组件内存布局： Entity1: [Transform][Health][Renderer] Entity2: [Transform][Health] Entity3: [Renderer][Transform] 访问所有Transform时的内存访问模式： 读取Entity1.Transform (缓存行1) 读取Entity2.Transform (缓存行2) 读取Entity3.Transform (缓存行3) → 缓存未命中率高 ECS内存布局： Transforms: [T1][T2][T3][T4][T5][T6][T7][T8]... Healths: [H1][H2][H3][H4][H5][H6][H7][H8]... Renderers: [R1][R2][R3][R4][R5][R6][R7][R8]... 访问所有Transform时的内存访问模式： 读取T1, T2, T3, T4... (都在连续的缓存行) → 缓存命中率高 缓存友好的代码：
// ECS System：连续处理相同类型的数据 public class MovementSystem : SystemBase&lt;TransformComponent, MovementComponent&gt; { public override void Execute(float deltaTime) { // 遍历连续的Transform数据 foreach (var entity in _entities) { var transform = GetC1(entity); var movement = GetC2(entity); // 连续的内存访问模式 transform.Position += movement.Velocity * deltaTime; } } } 4.3 与继承的性能对比 特性 继承 组件化（ECS） 实例创建 快 中等（需要组装） 方法调用 快（虚函数） 快（直接调用） 内存布局 分散 连续（ECS） 运行时组合 不支持 支持 缓存友好性 低 高（ECS） 代码复用 继承链 组件组合 实际性能考量：
在Godot C#环境中，对于中小型项目（&lt;1000个实体），性能差异通常可以忽略。选择架构时应更多考虑可维护性。
性能影响实际案例： 场景：100个敌人，每个有5个组件 继承方案： - 内存占用：~500KB - 更新耗时：0.5ms ECS方案： - 内存占用：~400KB（更紧凑） - 更新耗时：0.3ms（缓存友好） 差异：在60FPS下，0.2ms的差异可以忽略不计 → 选择更易于维护的方案 5. 实战指南 5.1 组件设计的步骤 步骤1：识别实体和职责
// 列出游戏中的实体 public enum EntityType { Player, // 玩家角色 Enemy, // 敌人 NPC, // NPC Item, // 物品 Projectile // 投射物 } // 列出每个实体的职责 // Player: 移动、战斗、背包、装备、技能 // Enemy: 移动、战斗、AI // Item: 可被拾取、可使用 步骤2：设计组件接口
// 定义组件接口 public interface IDamageable { void TakeDamage(int damage, Node source); bool IsDead { get; } } public interface IInteractable { void Interact(Node interactor); string InteractionPrompt { get; } } public interface ICollectible { void Collect(Node collector); string ItemId { get; } } 步骤3：实现基础组件
// 实现可复用的基础组件 public class HealthComponent : ComponentBase, IDamageable { [Export] public int MaxHealth { get; set; } = 100; public int CurrentHealth { get; private set; } protected override void OnInitialize() { CurrentHealth = MaxHealth; } public void TakeDamage(int damage, Node source) { CurrentHealth -= damage; if (CurrentHealth &lt;= 0) { Die(); } } private void Die() { EmitSignal(SignalName.Died); // 通知其他系统 MessageBus.Instance.Publish(new EntityDiedMessage { Entity = this }); } } 步骤4：组装实体
// 创建具体的实体类 public class Enemy : GameEntity { protected override void SetupComponents() { AddComponent&lt;HealthComponent&gt;(new HealthComponent { MaxHealth = 50 }); AddComponent&lt;MovementComponent&gt;(); AddComponent&lt;AIComponent&gt;(new AIComponent { DetectionRange = 10f, AttackRange = 2f }); AddComponent&lt;CombatComponent&gt;(new CombatComponent { AttackDamage = 5, AttackCooldown = 1.0f }); } } 5.2 常见错误：组件过度拆分 过度拆分的症状：
一个简单功能需要5个组件 组件之间高度依赖 为了修改一个行为需要修改多个组件 // 过度拆分的例子 public class Player : GameEntity { protected override void SetupComponents() { // 太多了！这些应该合并 AddComponent&lt;HorizontalMovementComponent&gt;(); AddComponent&lt;VerticalMovementComponent&gt;(); AddComponent&lt;JumpComponent&gt;(); AddComponent&lt;WalkComponent&gt;(); AddComponent&lt;RunComponent&gt;(); AddComponent&lt;SprintComponent&gt;(); } } // 更好的设计：合并相关功能 public class Player : GameEntity { protected override void SetupComponents() { AddComponent&lt;MovementComponent&gt;(new MovementComponent { WalkSpeed = 3f, RunSpeed = 6f, SprintSpeed = 9f, JumpForce = 10f }); } } 拆分原则：
单一职责：一个组件只做一件事 高内聚：组件内部的功能紧密相关 低耦合：组件之间的依赖最小化 合理的组件划分：
✓ HealthComponent - 管理生命值 ✓ MovementComponent - 管理移动 ✓ CombatComponent - 管理战斗 ✓ InventoryComponent - 管理背包 ✗ MovementComponent + AnimationComponent 分开（动画应该独立） ✗ HealthComponent + DamageReductionComponent 分开（应该合并） 5.3 测试策略 单元测试组件：
[Test] public void TestHealthComponent() { // Arrange var health = new HealthComponent { MaxHealth = 100 }; health.Initialize(); // Act health.TakeDamage(30, null); // Assert Assert.AreEqual(70, health.CurrentHealth); } [Test] public void TestHealthComponent_Death() { // Arrange var health = new HealthComponent { MaxHealth = 100 }; health.Initialize(); bool died = false; health.Died += () =&gt; died = true; // Act health.TakeDamage(100, null); // Assert Assert.IsTrue(died); Assert.IsTrue(health.IsDead); } 集成测试实体组装：
[Test] public void TestPlayerEntityAssembly() { // Arrange var player = new Player(); // Act player._Ready(); // 触发组件初始化 // Assert Assert.IsNotNull(player.GetComponent&lt;HealthComponent&gt;()); Assert.IsNotNull(player.GetComponent&lt;MovementComponent&gt;()); Assert.IsNotNull(player.GetComponent&lt;CombatComponent&gt;()); } Mock依赖：
[Test] public void TestCombatComponent_WithMockHealth() { // Arrange var mockHealth = Substitute.For&lt;IDamageable&gt;(); var combat = new CombatComponent(); combat.SetTarget(mockHealth); // Act combat.Attack(); // Assert mockHealth.Received().TakeDamage(Arg.Any&lt;int&gt;(), Arg.Any&lt;Node&gt;()); } 性能测试：
[Test] public void TestComponentLookupPerformance() { // 测试组件查找性能 var entity = new Entity(); for (int i = 0; i &lt; 100; i++) { entity.AddComponent&lt;TestComponent&gt;(); } var stopwatch = Stopwatch.StartNew(); for (int i = 0; i &lt; 10000; i++) { var component = entity.GetComponent&lt;TestComponent&gt;(); } stopwatch.Stop(); Assert.Less(stopwatch.ElapsedMilliseconds, 100); // 应该在100ms内完成 } 6. 组件化架构设计 组件化架构将游戏对象分解为可复用、可组合的独立单元，每个组件负责特定的功能模块。
6.1.1 ComponentBase 基类 首先定义所有组件的基类，提供通用的生命周期管理和事件系统。
// 文件路径: Scripts/Framework/Components/ComponentBase.cs using Godot; using System; using System.Collections.Generic; namespace GameFramework.Components { /// &lt;summary&gt; /// 组件基类 - 所有游戏组件的抽象基类 /// 提供生命周期管理、事件通信和序列化支持 /// &lt;/summary&gt; public abstract class ComponentBase : Node, IDisposable { #region 字段 // 组件是否已初始化 private bool _isInitialized = false; // 组件是否已启用 private bool _isEnabled = true; // 组件优先级 - 影响更新顺序，数值越小优先级越高 private int _priority = 0; // 组件唯一标识符 private string _componentId; // 组件拥有的子组件列表 private readonly List&lt;ComponentBase&gt; _childComponents = new List&lt;ComponentBase&gt;(); // 组件属性字典 - 用于运行时动态属性 private readonly Dictionary&lt;string, object&gt; _properties = new Dictionary&lt;string, object&gt;(); #endregion #region 属性 /// &lt;summary&gt; /// 组件是否已初始化 /// &lt;/summary&gt; public bool IsInitialized =&gt; _isInitialized; /// &lt;summary&gt; /// 组件是否已启用 /// &lt;/summary&gt; public bool IsEnabled { get =&gt; _isEnabled; set { if (_isEnabled != value) { _isEnabled = value; OnEnabledChanged(value); } } } /// &lt;summary&gt; /// 组件优先级 /// &lt;/summary&gt; public int Priority { get =&gt; _priority; set { _priority = value; // 通知父节点重新排序 EmitSignal(SignalName.PriorityChanged, value); } } /// &lt;summary&gt; /// 组件唯一ID /// &lt;/summary&gt; public string ComponentId =&gt; _componentId; /// &lt;summary&gt; /// 父组件 /// &lt;/summary&gt; public ComponentBase ParentComponent =&gt; GetParent() as ComponentBase; /// &lt;summary&gt; /// 根组件 /// &lt;/summary&gt; public ComponentBase RootComponent { get { var current = this; while (current.ParentComponent != null) { current = current.ParentComponent; } return current; } } #endregion #region 信号 [Signal] public delegate void InitializedEventHandler(); [Signal] public delegate void EnabledChangedEventHandler(bool enabled); [Signal] public delegate void PriorityChangedEventHandler(int priority); [Signal] public delegate void ComponentDestroyedEventHandler(); #endregion #region 生命周期 /// &lt;summary&gt; /// Godot 节点初始化入口 /// &lt;/summary&gt; public override void _Ready() { base._Ready(); // 生成唯一ID _componentId = Guid.NewGuid().ToString(&#34;N&#34;); // 设置节点名称为组件类型名（如果未设置） if (string.IsNullOrEmpty(Name) || Name == GetType().Name) { Name = $&#34;{GetType().Name}_{_componentId.Substring(0, 8)}&#34;; } // 执行组件初始化 Initialize(); } /// &lt;summary&gt; /// 每帧更新 /// &lt;/summary&gt; public override void _Process(double delta) { if (_isEnabled &amp;&amp; _isInitialized) { OnUpdate((float)delta); } } /// &lt;summary&gt; /// 固定时间间隔更新 /// &lt;/summary&gt; public override void _PhysicsProcess(double delta) { if (_isEnabled &amp;&amp; _isInitialized) { OnFixedUpdate((float)delta); } } /// &lt;summary&gt; /// 节点被销毁时调用 /// &lt;/summary&gt; public override void _ExitTree() { OnDestroy(); base._ExitTree(); } /// &lt;summary&gt; /// 组件初始化 - 子类必须实现 /// &lt;/summary&gt; protected virtual void Initialize() { if (_isInitialized) return; // 子类在此添加初始化逻辑 OnInitialize(); _isInitialized = true; EmitSignal(SignalName.Initialized); GD.Print($&#34;[ComponentBase] 组件已初始化: {GetType().Name} ({_componentId})&#34;); } /// &lt;summary&gt; /// 子类实现的具体初始化逻辑 /// &lt;/summary&gt; protected abstract void OnInitialize(); /// &lt;summary&gt; /// 子类实现的每帧更新逻辑 /// &lt;/summary&gt; protected virtual void OnUpdate(float deltaTime) { } /// &lt;summary&gt; /// 子类实现的固定更新逻辑 /// &lt;/summary&gt; protected virtual void OnFixedUpdate(float deltaTime) { } /// &lt;summary&gt; /// 子类实现的销毁逻辑 /// &lt;/summary&gt; protected virtual void OnDestroy() { EmitSignal(SignalName.ComponentDestroyed); Dispose(); } /// &lt;summary&gt; /// 启用状态改变时的回调 /// &lt;/summary&gt; protected virtual void OnEnabledChanged(bool enabled) { EmitSignal(SignalName.EnabledChanged, enabled); } #endregion #region 组件管理 /// &lt;summary&gt; /// 添加子组件 /// &lt;/summary&gt; public T AddComponent&lt;T&gt;() where T : ComponentBase, new() { var component = new T(); AddChild(component); _childComponents.Add(component); // 按优先级排序 SortChildComponents(); return component; } /// &lt;summary&gt; /// 获取组件 /// &lt;/summary&gt; public T GetComponent&lt;T&gt;() where T : ComponentBase { foreach (var child in _childComponents) { if (child is T t) return t; } return null; } /// &lt;summary&gt; /// 获取所有指定类型的组件 /// &lt;/summary&gt; public List&lt;T&gt; GetComponents&lt;T&gt;() where T : ComponentBase { var result = new List&lt;T&gt;(); foreach (var child in _childComponents) { if (child is T t) result.Add(t); } return result; } /// &lt;summary&gt; /// 移除组件 /// &lt;/summary&gt; public bool RemoveComponent&lt;T&gt;() where T : ComponentBase { var component = GetComponent&lt;T&gt;(); if (component != null) { _childComponents.Remove(component); component.QueueFree(); return true; } return false; } /// &lt;summary&gt; /// 按优先级排序子组件 /// &lt;/summary&gt; private void SortChildComponents() { _childComponents.Sort((a, b) =&gt; a._priority.CompareTo(b._priority)); } #endregion #region 属性系统 /// &lt;summary&gt; /// 设置动态属性 /// &lt;/summary&gt; public void SetProperty(string key, object value) { _properties[key] = value; } /// &lt;summary&gt; /// 获取动态属性 /// &lt;/summary&gt; public T GetProperty&lt;T&gt;(string key, T defaultValue = default) { if (_properties.TryGetValue(key, out var value) &amp;&amp; value is T t) { return t; } return defaultValue; } /// &lt;summary&gt; /// 检查属性是否存在 /// &lt;/summary&gt; public bool HasProperty(string key) { return _properties.ContainsKey(key); } /// &lt;summary&gt; /// 移除属性 /// &lt;/summary&gt; public bool RemoveProperty(string key) { return _properties.Remove(key); } #endregion #region IDisposable /// &lt;summary&gt; /// 释放资源 /// &lt;/summary&gt; public virtual void Dispose() { _childComponents.Clear(); _properties.Clear(); } #endregion } } 6.1.2 组件生命周期 组件生命周期管理确保组件按正确顺序初始化和销毁。
// 文件路径: Scripts/Framework/Components/Lifecycle/LifecycleManager.cs using Godot; using System; using System.Collections.Generic; using System.Linq; namespace GameFramework.Components.Lifecycle { /// &lt;summary&gt; /// 生命周期管理器 - 管理组件的创建、初始化和销毁流程 /// &lt;/summary&gt; public class LifecycleManager : Node { #region 单例 private static LifecycleManager _instance; public static LifecycleManager Instance { get { if (_instance == null) { // 尝试从场景中获取 _instance = Engine.GetSingleton(nameof(LifecycleManager)) as LifecycleManager; // 如果不存在，创建新的实例 if (_instance == null) { _instance = new LifecycleManager(); Engine.RegisterSingleton(nameof(LifecycleManager), _instance); } } return _instance; } } #endregion #region 字段 // 待初始化的组件队列 private readonly Queue&lt;ComponentBase&gt; _initializationQueue = new Queue&lt;ComponentBase&gt;(); // 活跃组件列表 private readonly List&lt;ComponentBase&gt; _activeComponents = new List&lt;ComponentBase&gt;(); // 待销毁组件队列 private readonly Queue&lt;ComponentBase&gt; _destructionQueue = new Queue&lt;ComponentBase&gt;(); // 是否正在处理生命周期 private bool _isProcessingLifecycle = false; #endregion #region 属性 /// &lt;summary&gt; /// 活跃组件数量 /// &lt;/summary&gt; public int ActiveComponentCount =&gt; _activeComponents.Count; #endregion #region Godot 生命周期 public override void _Ready() { base._Ready(); // 设置处理模式为始终运行 ProcessMode = ProcessModeEnum.Always; } public override void _Process(double delta) { // 处理生命周期队列 ProcessLifecycleQueues(); } #endregion #region 生命周期管理 /// &lt;summary&gt; /// 注册组件到生命周期管理器 /// &lt;/summary&gt; public void RegisterComponent(ComponentBase component) { if (component == null || component.IsInitialized) return; // 添加到初始化队列 _initializationQueue.Enqueue(component); GD.Print($&#34;[LifecycleManager] 组件已注册: {component.GetType().Name}&#34;); } /// &lt;summary&gt; /// 注销组件 /// &lt;/summary&gt; public void UnregisterComponent(ComponentBase component) { if (component == null) return; // 从活跃列表移除 _activeComponents.Remove(component); // 添加到销毁队列 _destructionQueue.Enqueue(component); GD.Print($&#34;[LifecycleManager] 组件已注销: {component.GetType().Name}&#34;); } /// &lt;summary&gt; /// 处理生命周期队列 /// &lt;/summary&gt; private void ProcessLifecycleQueues() { if (_isProcessingLifecycle) return; _isProcessingLifecycle = true; try { // 处理初始化队列 ProcessInitializationQueue(); // 处理销毁队列 ProcessDestructionQueue(); } finally { _isProcessingLifecycle = false; } } /// &lt;summary&gt; /// 处理初始化队列 /// &lt;/summary&gt; private void ProcessInitializationQueue() { // 限制每帧初始化的组件数量，避免卡顿 const int maxInitializationsPerFrame = 10; int initializedCount = 0; while (_initializationQueue.Count &gt; 0 &amp;&amp; initializedCount &lt; maxInitializationsPerFrame) { var component = _initializationQueue.Dequeue(); if (component != null &amp;&amp; !component.IsInitialized) { // 添加到活跃列表 _activeComponents.Add(component); // 按优先级排序 SortActiveComponents(); initializedCount++; } } } /// &lt;summary&gt; /// 处理销毁队列 /// &lt;/summary&gt; private void ProcessDestructionQueue() { while (_destructionQueue.Count &gt; 0) { var component = _destructionQueue.Dequeue(); if (component != null) { // 清理引用 if (!component.IsQueuedForDeletion()) { component.QueueFree(); } } } } /// &lt;summary&gt; /// 按优先级排序活跃组件 /// &lt;/summary&gt; private void SortActiveComponents() { _activeComponents.Sort((a, b) =&gt; { // 使用反射获取优先级（因为 Priority 是受保护的） int priorityA = GetComponentPriority(a); int priorityB = GetComponentPriority(b); return priorityA.CompareTo(priorityB); }); } /// &lt;summary&gt; /// 获取组件优先级 /// &lt;/summary&gt; private int GetComponentPriority(ComponentBase component) { // 通过属性访问优先级 var property = component.GetType().GetProperty(&#34;Priority&#34;); if (property != null) { return (int)property.GetValue(component); } return 0; } #endregion #region 批量操作 /// &lt;summary&gt; /// 启用所有组件 /// &lt;/summary&gt; public void EnableAllComponents() { foreach (var component in _activeComponents) { if (component != null) { component.IsEnabled = true; } } } /// &lt;summary&gt; /// 禁用所有组件 /// &lt;/summary&gt; public void DisableAllComponents() { foreach (var component in _activeComponents) { if (component != null) { component.IsEnabled = false; } } } /// &lt;summary&gt; /// 暂停指定类型的组件 /// &lt;/summary&gt; public void PauseComponents&lt;T&gt;() where T : ComponentBase { var components = _activeComponents.OfType&lt;T&gt;().ToList(); foreach (var component in components) { component.IsEnabled = false; } } /// &lt;summary&gt; /// 恢复指定类型的组件 /// &lt;/summary&gt; public void ResumeComponents&lt;T&gt;() where T : ComponentBase { var components = _activeComponents.OfType&lt;T&gt;().ToList(); foreach (var component in components) { component.IsEnabled = true; } } /// &lt;summary&gt; /// 销毁所有组件 /// &lt;/summary&gt; public void DestroyAllComponents() { var components = new List&lt;ComponentBase&gt;(_activeComponents); foreach (var component in components) { UnregisterComponent(component); } } #endregion #region 查询 /// &lt;summary&gt; /// 获取指定类型的所有组件 /// &lt;/summary&gt; public List&lt;T&gt; GetComponentsOfType&lt;T&gt;() where T : ComponentBase { return _activeComponents.OfType&lt;T&gt;().ToList(); } /// &lt;summary&gt; /// 查找组件 /// &lt;/summary&gt; public T FindComponent&lt;T&gt;(Func&lt;T, bool&gt; predicate) where T : ComponentBase { return _activeComponents.OfType&lt;T&gt;().FirstOrDefault(predicate); } #endregion } } 6.1.3 组件间通信 组件间通信是组件化架构的核心，通过事件系统和消息总线实现松耦合通信。
// 文件路径: Scripts/Framework/Components/Communication/MessageBus.cs using Godot; using System; using System.Collections.Generic; namespace GameFramework.Components.Communication { /// &lt;summary&gt; /// 消息基类 - 所有组件间消息的基类 /// &lt;/summary&gt; public abstract class MessageBase { /// &lt;summary&gt; /// 消息发送时间 /// &lt;/summary&gt; public float Timestamp { get; private set; } /// &lt;summary&gt; /// 消息发送者ID /// &lt;/summary&gt; public string SenderId { get; set; } /// &lt;summary&gt; /// 消息是否已处理 /// &lt;/summary&gt; public bool IsHandled { get; set; } protected MessageBase() { Timestamp = Time.GetTicksMsec() / 1000f; } /// &lt;summary&gt; /// 标记消息为已处理 /// &lt;/summary&gt; public void MarkHandled() { IsHandled = true; } } /// &lt;summary&gt; /// 通用消息 - 用于简单的事件通知 /// &lt;/summary&gt; public class GenericMessage : MessageBase { /// &lt;summary&gt; /// 消息类型标识 /// &lt;/summary&gt; public string MessageType { get; set; } /// &lt;summary&gt; /// 消息数据 /// &lt;/summary&gt; public Dictionary&lt;string, object&gt; Data { get; set; } public GenericMessage(string messageType) { MessageType = messageType; Data = new Dictionary&lt;string, object&gt;(); } /// &lt;summary&gt; /// 添加数据 /// &lt;/summary&gt; public GenericMessage WithData(string key, object value) { Data[key] = value; return this; } } /// &lt;summary&gt; /// 消息总线 - 全局消息分发系统 /// &lt;/summary&gt; public class MessageBus : Node { #region 单例 private static MessageBus _instance; public static MessageBus Instance { get { if (_instance == null) { _instance = new MessageBus(); Engine.RegisterSingleton(nameof(MessageBus), _instance); } return _instance; } } #endregion #region 委托和事件 /// &lt;summary&gt; /// 消息处理委托 /// &lt;/summary&gt; public delegate void MessageHandler&lt;T&gt;(T message) where T : MessageBase; /// &lt;summary&gt; /// 通用消息处理委托 /// &lt;/summary&gt; public delegate void GenericMessageHandler(GenericMessage message); #endregion #region 字段 // 类型化消息处理器字典 private readonly Dictionary&lt;Type, Delegate&gt; _typedHandlers = new Dictionary&lt;Type, Delegate&gt;(); // 通用消息处理器字典 - 按消息类型分组 private readonly Dictionary&lt;string, List&lt;GenericMessageHandler&gt;&gt; _genericHandlers = new Dictionary&lt;string, List&lt;GenericMessageHandler&gt;&gt;(); // 消息队列 - 用于延迟处理 private readonly Queue&lt;MessageBase&gt; _messageQueue = new Queue&lt;MessageBase&gt;(); // 处理器优先级字典 private readonly Dictionary&lt;Delegate, int&gt; _handlerPriorities = new Dictionary&lt;Delegate, int&gt;(); #endregion #region 订阅 /// &lt;summary&gt; /// 订阅类型化消息 /// &lt;/summary&gt; public void Subscribe&lt;T&gt;(MessageHandler&lt;T&gt; handler, int priority = 0) where T : MessageBase { var messageType = typeof(T); if (!_typedHandlers.ContainsKey(messageType)) { _typedHandlers[messageType] = null; } _typedHandlers[messageType] = (MessageHandler&lt;T&gt;)_typedHandlers[messageType] + handler; _handlerPriorities[handler] = priority; } /// &lt;summary&gt; /// 订阅通用消息 /// &lt;/summary&gt; public void Subscribe(string messageType, GenericMessageHandler handler) { if (!_genericHandlers.ContainsKey(messageType)) { _genericHandlers[messageType] = new List&lt;GenericMessageHandler&gt;(); } if (!_genericHandlers[messageType].Contains(handler)) { _genericHandlers[messageType].Add(handler); } } /// &lt;summary&gt; /// 取消订阅类型化消息 /// &lt;/summary&gt; public void Unsubscribe&lt;T&gt;(MessageHandler&lt;T&gt; handler) where T : MessageBase { var messageType = typeof(T); if (_typedHandlers.ContainsKey(messageType)) { _typedHandlers[messageType] = (MessageHandler&lt;T&gt;)_typedHandlers[messageType] - handler; _handlerPriorities.Remove(handler); } } /// &lt;summary&gt; /// 取消订阅通用消息 /// &lt;/summary&gt; public void Unsubscribe(string messageType, GenericMessageHandler handler) { if (_genericHandlers.ContainsKey(messageType)) { _genericHandlers[messageType].Remove(handler); } } #endregion #region 发布 /// &lt;summary&gt; /// 立即发布消息 /// &lt;/summary&gt; public void Publish&lt;T&gt;(T message) where T : MessageBase { var messageType = typeof(T); // 处理类型化消息 if (_typedHandlers.ContainsKey(messageType) &amp;&amp; _typedHandlers[messageType] != null) { var handler = (MessageHandler&lt;T&gt;)_typedHandlers[messageType]; handler?.Invoke(message); } // 处理通用消息 if (message is GenericMessage genericMessage) { PublishGeneric(genericMessage); } } /// &lt;summary&gt; /// 发布通用消息 /// &lt;/summary&gt; private void PublishGeneric(GenericMessage message) { if (_genericHandlers.ContainsKey(message.MessageType)) { var handlers = _genericHandlers[message.MessageType]; foreach (var handler in handlers) { try { handler.Invoke(message); // 如果消息被标记为已处理，停止传播 if (message.IsHandled) break; } catch (Exception ex) { GD.PushError($&#34;[MessageBus] 消息处理器异常: {ex.Message}&#34;); } } } } /// &lt;summary&gt; /// 延迟发布消息（下一帧处理） /// &lt;/summary&gt; public void PublishDelayed&lt;T&gt;(T message) where T : MessageBase { _messageQueue.Enqueue(message); } /// &lt;summary&gt; /// 每帧处理延迟消息 /// &lt;/summary&gt; public override void _Process(double delta) { // 处理延迟消息队列 while (_messageQueue.Count &gt; 0) { var message = _messageQueue.Dequeue(); Publish(message); } } #endregion #region 查询 /// &lt;summary&gt; /// 发布消息并等待结果 /// &lt;/summary&gt; public TResult Query&lt;TMessage, TResult&gt;(TMessage message, Func&lt;TMessage, TResult&gt; queryHandler) where TMessage : MessageBase { return queryHandler.Invoke(message); } /// &lt;summary&gt; /// 是否存在指定类型的处理器 /// &lt;/summary&gt; public bool HasHandlers&lt;T&gt;() where T : MessageBase { return _typedHandlers.ContainsKey(typeof(T)) &amp;&amp; _typedHandlers[typeof(T)] != null; } /// &lt;summary&gt; /// 是否存在通用消息处理器 /// &lt;/summary&gt; public bool HasHandlers(string messageType) { return _genericHandlers.ContainsKey(messageType) &amp;&amp; _genericHandlers[messageType].Count &gt; 0; } #endregion #region 清理 /// &lt;summary&gt; /// 清理所有订阅 /// &lt;/summary&gt; public void ClearAllSubscriptions() { _typedHandlers.Clear(); _genericHandlers.Clear(); _handlerPriorities.Clear(); _messageQueue.Clear(); } /// &lt;summary&gt; /// 清理指定类型的订阅 /// &lt;/summary&gt; public void ClearSubscriptions&lt;T&gt;() where T : MessageBase { _typedHandlers.Remove(typeof(T)); } /// &lt;summary&gt; /// 清理指定通用消息的订阅 /// &lt;/summary&gt; public void ClearSubscriptions(string messageType) { _genericHandlers.Remove(messageType); } #endregion } } 使用示例：
// 文件路径: Scripts/Examples/ComponentCommunicationExample.cs using Godot; using GameFramework.Components; using GameFramework.Components.Communication; namespace GameFramework.Examples { /// &lt;summary&gt; /// 生命值变化消息 /// &lt;/summary&gt; public class HealthChangedMessage : MessageBase { public int CurrentHealth { get; set; } public int MaxHealth { get; set; } public int ChangeAmount { get; set; } } /// &lt;summary&gt; /// 健康组件 - 管理实体生命值 /// &lt;/summary&gt; public class HealthComponent : ComponentBase { private int _currentHealth = 100; private int _maxHealth = 100; public int CurrentHealth =&gt; _currentHealth; public int MaxHealth =&gt; _maxHealth; protected override void OnInitialize() { // 组件初始化完成 } /// &lt;summary&gt; /// 受到伤害 /// &lt;/summary&gt; public void TakeDamage(int damage) { int oldHealth = _currentHealth; _currentHealth = Mathf.Max(0, _currentHealth - damage); // 发布生命值变化消息 var message = new HealthChangedMessage { SenderId = ComponentId, CurrentHealth = _currentHealth, MaxHealth = _maxHealth, ChangeAmount = _currentHealth - oldHealth }; MessageBus.Instance.Publish(message); if (_currentHealth &lt;= 0) { // 发布死亡消息 MessageBus.Instance.Publish(new GenericMessage(&#34;EntityDied&#34;) .WithData(&#34;EntityId&#34;, ComponentId)); } } /// &lt;summary&gt; /// 治疗 /// &lt;/summary&gt; public void Heal(int amount) { int oldHealth = _currentHealth; _currentHealth = Mathf.Min(_maxHealth, _currentHealth + amount); // 发布生命值变化消息 var message = new HealthChangedMessage { SenderId = ComponentId, CurrentHealth = _currentHealth, MaxHealth = _maxHealth, ChangeAmount = _currentHealth - oldHealth }; MessageBus.Instance.Publish(message); } } /// &lt;summary&gt; /// UI 组件 - 显示生命值 /// &lt;/summary&gt; public class HealthUIComponent : ComponentBase { private Label _healthLabel; private ProgressBar _healthBar; protected override void OnInitialize() { // 订阅生命值变化消息 MessageBus.Instance.Subscribe&lt;HealthChangedMessage&gt;(OnHealthChanged); // 创建UI元素 _healthLabel = new Label(); _healthBar = new ProgressBar(); AddChild(_healthLabel); AddChild(_healthBar); } /// &lt;summary&gt; /// 生命值变化回调 /// &lt;/summary&gt; private void OnHealthChanged(HealthChangedMessage message) { // 更新UI显示 _healthLabel.Text = $&#34;HP: {message.CurrentHealth}/{message.MaxHealth}&#34;; _healthBar.MaxValue = message.MaxHealth; _healthBar.Value = message.CurrentHealth; // 根据血量改变颜色 float healthPercent = (float)message.CurrentHealth / message.MaxHealth; if (healthPercent &lt; 0.3f) { _healthLabel.Modulate = Colors.Red; } else if (healthPercent &lt; 0.6f) { _healthLabel.Modulate = Colors.Yellow; } else { _healthLabel.Modulate = Colors.Green; } } protected override void OnDestroy() { // 取消订阅 MessageBus.Instance.Unsubscribe&lt;HealthChangedMessage&gt;(OnHealthChanged); base.OnDestroy(); } } } 6.2 轻量级 ECS 模拟 ECS（Entity-Component-System）是游戏开发中广泛使用的高性能架构模式。本节实现一个适合 Godot C# 的轻量级 ECS 系统。
6.2.1 Entity 类设计 Entity 是 ECS 中的基本单位，本身不包含数据，仅作为组件的容器。
// 文件路径: Scripts/Framework/ECS/Entity.cs using Godot; using System; using System.Collections.Generic; namespace GameFramework.ECS { /// &lt;summary&gt; /// 实体类 - ECS架构中的基本单位 /// 实体本身无状态，仅作为组件的容器和标识符 /// &lt;/summary&gt; public class Entity : IDisposable { #region 字段 // 实体唯一标识符 private readonly int _id; // 实体名称（可选） private string _name; // 组件字典 - 按类型存储 private readonly Dictionary&lt;Type, IComponent&gt; _components = new Dictionary&lt;Type, IComponent&gt;(); // 组件列表 - 保持插入顺序 private readonly List&lt;IComponent&gt; _componentList = new List&lt;IComponent&gt;(); // 实体是否激活 private bool _isActive = true; // 所属世界 private World _world; // 实体创建时间 private readonly float _creationTime; #endregion #region 属性 /// &lt;summary&gt; /// 实体唯一ID /// &lt;/summary&gt; public int Id =&gt; _id; /// &lt;summary&gt; /// 实体名称 /// &lt;/summary&gt; public string Name { get =&gt; _name; set =&gt; _name = value; } /// &lt;summary&gt; /// 实体是否激活 /// &lt;/summary&gt; public bool IsActive { get =&gt; _isActive; set { if (_isActive != value) { _isActive = value; OnActiveStateChanged(value); } } } /// &lt;summary&gt; /// 所属世界 /// &lt;/summary&gt; public World World =&gt; _world; /// &lt;summary&gt; /// 实体存活时间（秒） /// &lt;/summary&gt; public float Lifetime =&gt; (Time.GetTicksMsec() / 1000f) - _creationTime; /// &lt;summary&gt; /// 组件数量 /// &lt;/summary&gt; public int ComponentCount =&gt; _components.Count; #endregion #region 构造函数 public Entity(int id, World world) { _id = id; _world = world; _creationTime = Time.GetTicksMsec() / 1000f; _name = $&#34;Entity_{id}&#34;; } #endregion #region 组件管理 /// &lt;summary&gt; /// 添加组件 /// &lt;/summary&gt; public T AddComponent&lt;T&gt;(T component) where T : class, IComponent { var type = typeof(T); // 检查是否已存在该类型组件 if (_components.ContainsKey(type)) { GD.PushWarning($&#34;[Entity] 实体 {_id} 已存在组件类型 {type.Name}，将替换旧组件&#34;); RemoveComponent&lt;T&gt;(); } // 设置组件的所属实体 component.Entity = this; // 添加到字典和列表 _components[type] = component; _componentList.Add(component); // 通知世界组件已添加 _world?.OnComponentAdded(this, component); // 调用组件初始化 component.Initialize(); return component; } /// &lt;summary&gt; /// 添加组件（自动创建实例） /// &lt;/summary&gt; public T AddComponent&lt;T&gt;() where T : class, IComponent, new() { return AddComponent(new T()); } /// &lt;summary&gt; /// 获取组件 /// &lt;/summary&gt; public T GetComponent&lt;T&gt;() where T : class, IComponent { if (_components.TryGetValue(typeof(T), out var component)) { return component as T; } return null; } /// &lt;summary&gt; /// 尝试获取组件 /// &lt;/summary&gt; public bool TryGetComponent&lt;T&gt;(out T component) where T : class, IComponent { component = GetComponent&lt;T&gt;(); return component != null; } /// &lt;summary&gt; /// 检查是否拥有组件 /// &lt;/summary&gt; public bool HasComponent&lt;T&gt;() where T : class, IComponent { return _components.ContainsKey(typeof(T)); } /// &lt;summary&gt; /// 检查是否拥有所有指定类型的组件 /// &lt;/summary&gt; public bool HasComponents(params Type[] componentTypes) { foreach (var type in componentTypes) { if (!_components.ContainsKey(type)) return false; } return true; } /// &lt;summary&gt; /// 移除组件 /// &lt;/summary&gt; public bool RemoveComponent&lt;T&gt;() where T : class, IComponent { var type = typeof(T); if (_components.TryGetValue(type, out var component)) { // 通知世界组件将被移除 _world?.OnComponentRemoved(this, component); // 调用组件清理 component.Dispose(); // 从集合中移除 _components.Remove(type); _componentList.Remove(component); return true; } return false; } /// &lt;summary&gt; /// 移除所有组件 /// &lt;/summary&gt; public void RemoveAllComponents() { // 倒序遍历以避免修改集合时的迭代问题 for (int i = _componentList.Count - 1; i &gt;= 0; i--) { var component = _componentList[i]; _world?.OnComponentRemoved(this, component); component.Dispose(); } _components.Clear(); _componentList.Clear(); } /// &lt;summary&gt; /// 获取所有组件 /// &lt;/summary&gt; public IEnumerable&lt;IComponent&gt; GetAllComponents() { return _componentList; } /// &lt;summary&gt; /// 替换组件 /// &lt;/summary&gt; public T ReplaceComponent&lt;T&gt;(T newComponent) where T : class, IComponent { RemoveComponent&lt;T&gt;(); return AddComponent(newComponent); } #endregion #region 实体操作 /// &lt;summary&gt; /// 克隆实体及其所有组件 /// &lt;/summary&gt; public Entity Clone() { var newEntity = _world.CreateEntity(); newEntity._name = _name + &#34;_Clone&#34;; // 克隆所有组件 foreach (var component in _componentList) { if (component is ICloneable cloneable) { var clonedComponent = cloneable.Clone() as IComponent; if (clonedComponent != null) { // 使用反射获取组件类型并添加到新实体 var type = component.GetType(); var method = typeof(Entity).GetMethod(nameof(AddComponent), new[] { type }); method?.Invoke(newEntity, new object[] { clonedComponent }); } } } return newEntity; } /// &lt;summary&gt; /// 销毁实体 /// &lt;/summary&gt; public void Destroy() { // 从世界中移除 _world?.RemoveEntity(this); // 清理资源 Dispose(); } /// &lt;summary&gt; /// 激活状态改变回调 /// &lt;/summary&gt; protected virtual void OnActiveStateChanged(bool active) { // 激活/禁用所有组件 foreach (var component in _componentList) { if (component is IActivatable activatable) { activatable.SetActive(active); } } } #endregion #region IDisposable public void Dispose() { RemoveAllComponents(); _world = null; } #endregion #region 运算符重载 /// &lt;summary&gt; /// 隐式转换为布尔值（检查实体是否有效） /// &lt;/summary&gt; public static implicit operator bool(Entity entity) { return entity != null &amp;&amp; entity._isActive; } /// &lt;summary&gt; /// 相等性比较（基于ID） /// &lt;/summary&gt; public override bool Equals(object obj) { return obj is Entity other &amp;&amp; _id == other._id; } public override int GetHashCode() { return _id.GetHashCode(); } public static bool operator ==(Entity a, Entity b) { if (ReferenceEquals(a, null) &amp;&amp; ReferenceEquals(b, null)) return true; if (ReferenceEquals(a, null) || ReferenceEquals(b, null)) return false; return a._id == b._id; } public static bool operator !=(Entity a, Entity b) { return !(a == b); } #endregion #region ToString public override string ToString() { return $&#34;Entity[{_id}] &#39;{_name}&#39; ({_components.Count} components)&#34;; } #endregion } } 6.2.2 组件接口定义 定义 ECS 组件的基础接口。
// 文件路径: Scripts/Framework/ECS/IComponent.cs using System; namespace GameFramework.ECS { /// &lt;summary&gt; /// 组件接口 - ECS架构中所有组件必须实现的接口 /// &lt;/summary&gt; public interface IComponent : IDisposable { /// &lt;summary&gt; /// 组件所属的实体 /// &lt;/summary&gt; Entity Entity { get; set; } /// &lt;summary&gt; /// 组件是否激活 /// &lt;/summary&gt; bool IsActive { get; } /// &lt;summary&gt; /// 初始化组件 /// &lt;/summary&gt; void Initialize(); /// &lt;summary&gt; /// 设置激活状态 /// &lt;/summary&gt; void SetActive(bool active); } /// &lt;summary&gt; /// 可激活接口 /// &lt;/summary&gt; public interface IActivatable { void SetActive(bool active); } /// &lt;summary&gt; /// 可更新组件接口 /// &lt;/summary&gt; public interface IUpdatableComponent : IComponent { /// &lt;summary&gt; /// 更新组件 /// &lt;/summary&gt; void Update(float deltaTime); } /// &lt;summary&gt; /// 可固定更新组件接口 /// &lt;/summary&gt; public interface IFixedUpdatableComponent : IComponent { /// &lt;summary&gt; /// 固定更新组件 /// &lt;/summary&gt; void FixedUpdate(float fixedDeltaTime); } } 6.2.3 System 类设计 System 负责处理具有特定组件组合的实体。
// 文件路径: Scripts/Framework/ECS/SystemBase.cs using Godot; using System; using System.Collections.Generic; namespace GameFramework.ECS { /// &lt;summary&gt; /// 系统执行类型 /// &lt;/summary&gt; public enum SystemExecutionType { /// &lt;summary&gt; /// 更新系统 - 每帧执行 /// &lt;/summary&gt; Update, /// &lt;summary&gt; /// 固定更新系统 - 固定时间间隔执行 /// &lt;/summary&gt; FixedUpdate, /// &lt;summary&gt; /// 渲染系统 - 渲染前执行 /// &lt;/summary&gt; Render, /// &lt;summary&gt; /// 事件系统 - 响应事件时执行 /// &lt;/summary&gt; Event } /// &lt;summary&gt; /// 系统基类 - ECS架构中的处理器基类 /// &lt;/summary&gt; public abstract class SystemBase : IDisposable { #region 字段 // 系统优先级（数值越小优先级越高） private int _priority = 0; // 系统是否启用 private bool _isEnabled = true; // 系统执行类型 private SystemExecutionType _executionType = SystemExecutionType.Update; // 系统关注的组件类型 private readonly List&lt;Type&gt; _requiredComponentTypes = new List&lt;Type&gt;(); // 系统处理的实体列表 protected readonly List&lt;Entity&gt; _entities = new List&lt;Entity&gt;(); // 所属世界 protected World _world; #endregion #region 属性 /// &lt;summary&gt; /// 系统优先级 /// &lt;/summary&gt; public int Priority { get =&gt; _priority; set =&gt; _priority = value; } /// &lt;summary&gt; /// 系统是否启用 /// &lt;/summary&gt; public bool IsEnabled { get =&gt; _isEnabled; set =&gt; _isEnabled = value; } /// &lt;summary&gt; /// 系统执行类型 /// &lt;/summary&gt; public SystemExecutionType ExecutionType =&gt; _executionType; /// &lt;summary&gt; /// 系统名称 /// &lt;/summary&gt; public virtual string SystemName =&gt; GetType().Name; /// &lt;summary&gt; /// 处理的实体数量 /// &lt;/summary&gt; public int EntityCount =&gt; _entities.Count; #endregion #region 构造函数 protected SystemBase(SystemExecutionType executionType = SystemExecutionType.Update) { _executionType = executionType; } #endregion #region 抽象方法 /// &lt;summary&gt; /// 初始化系统 /// &lt;/summary&gt; public abstract void Initialize(World world); /// &lt;summary&gt; /// 执行系统逻辑 /// &lt;/summary&gt; public abstract void Execute(float deltaTime); /// &lt;summary&gt; /// 系统启动时调用 /// &lt;/summary&gt; public virtual void OnStart() { } /// &lt;summary&gt; /// 系统停止时调用 /// &lt;/summary&gt; public virtual void OnStop() { } /// &lt;summary&gt; /// 实体进入系统时调用 /// &lt;/summary&gt; public virtual void OnEntityEnter(Entity entity) { } /// &lt;summary&gt; /// 实体离开系统时调用 /// &lt;/summary&gt; public virtual void OnEntityExit(Entity entity) { } #endregion #region 实体管理 /// &lt;summary&gt; /// 添加实体到系统 /// &lt;/summary&gt; public void AddEntity(Entity entity) { if (!_entities.Contains(entity)) { _entities.Add(entity); OnEntityEnter(entity); } } /// &lt;summary&gt; /// 从系统移除实体 /// &lt;/summary&gt; public void RemoveEntity(Entity entity) { if (_entities.Remove(entity)) { OnEntityExit(entity); } } /// &lt;summary&gt; /// 检查实体是否符合系统要求 /// &lt;/summary&gt; public bool IsEntityValid(Entity entity) { if (entity == null || !entity.IsActive) return false; foreach (var componentType in _requiredComponentTypes) { // 使用反射检查组件类型 var method = typeof(Entity).GetMethod(nameof(Entity.HasComponent)); var genericMethod = method.MakeGenericMethod(componentType); var result = genericMethod.Invoke(entity, null); if (!(bool)result) return false; } return true; } /// &lt;summary&gt; /// 刷新实体列表 /// &lt;/summary&gt; public void RefreshEntities() { // 移除无效实体 for (int i = _entities.Count - 1; i &gt;= 0; i--) { if (!IsEntityValid(_entities[i])) { var entity = _entities[i]; _entities.RemoveAt(i); OnEntityExit(entity); } } } /// &lt;summary&gt; /// 添加必需的组件类型 /// &lt;/summary&gt; protected void RequireComponent&lt;T&gt;() where T : class, IComponent { _requiredComponentTypes.Add(typeof(T)); } /// &lt;summary&gt; /// 添加必需的组件类型 /// &lt;/summary&gt; protected void RequireComponent(Type componentType) { if (!typeof(IComponent).IsAssignableFrom(componentType)) { throw new ArgumentException($&#34;类型 {componentType.Name} 必须实现 IComponent 接口&#34;); } _requiredComponentTypes.Add(componentType); } #endregion #region 工具方法 /// &lt;summary&gt; /// 获取系统中的所有组件 /// &lt;/summary&gt; public IEnumerable&lt;T&gt; GetComponents&lt;T&gt;() where T : class, IComponent { foreach (var entity in _entities) { var component = entity.GetComponent&lt;T&gt;(); if (component != null) { yield return component; } } } /// &lt;summary&gt; /// 获取实体组件 /// &lt;/summary&gt; protected T GetComponent&lt;T&gt;(Entity entity) where T : class, IComponent { return entity?.GetComponent&lt;T&gt;(); } #endregion #region IDisposable public virtual void Dispose() { OnStop(); _entities.Clear(); _requiredComponentTypes.Clear(); } #endregion } /// &lt;summary&gt; /// 泛型系统基类 - 提供类型安全的组件访问 /// &lt;/summary&gt; public abstract class SystemBase&lt;T1&gt; : SystemBase where T1 : class, IComponent { protected SystemBase(SystemExecutionType executionType = SystemExecutionType.Update) : base(executionType) { RequireComponent&lt;T1&gt;(); } /// &lt;summary&gt; /// 获取组件 /// &lt;/summary&gt; protected T1 GetC1(Entity entity) =&gt; entity.GetComponent&lt;T1&gt;(); } /// &lt;summary&gt; /// 双组件系统基类 /// &lt;/summary&gt; public abstract class SystemBase&lt;T1, T2&gt; : SystemBase&lt;T1&gt; where T1 : class, IComponent where T2 : class, IComponent { protected SystemBase(SystemExecutionType executionType = SystemExecutionType.Update) : base(executionType) { RequireComponent&lt;T2&gt;(); } /// &lt;summary&gt; /// 获取第二个组件 /// &lt;/summary&gt; protected T2 GetC2(Entity entity) =&gt; entity.GetComponent&lt;T2&gt;(); } /// &lt;summary&gt; /// 三组件系统基类 /// &lt;/summary&gt; public abstract class SystemBase&lt;T1, T2, T3&gt; : SystemBase&lt;T1, T2&gt; where T1 : class, IComponent where T2 : class, IComponent where T3 : class, IComponent { protected SystemBase(SystemExecutionType executionType = SystemExecutionType.Update) : base(executionType) { RequireComponent&lt;T3&gt;(); } /// &lt;summary&gt; /// 获取第三个组件 /// &lt;/summary&gt; protected T3 GetC3(Entity entity) =&gt; entity.GetComponent&lt;T3&gt;(); } } 6.2.4 World 管理器 World 是 ECS 系统的核心管理器，负责协调实体、组件和系统。
// 文件路径: Scripts/Framework/ECS/World.cs using Godot; using System; using System.Collections.Generic; using System.Linq; namespace GameFramework.ECS { /// &lt;summary&gt; /// 世界类 - ECS架构的核心管理器 /// 负责管理所有实体、系统和组件的生命周期 /// &lt;/summary&gt; public class World : Node { #region 字段 // 实体字典 private readonly Dictionary&lt;int, Entity&gt; _entities = new Dictionary&lt;int, Entity&gt;(); // 系统列表 private readonly List&lt;SystemBase&gt; _updateSystems = new List&lt;SystemBase&gt;(); private readonly List&lt;SystemBase&gt; _fixedUpdateSystems = new List&lt;SystemBase&gt;(); private readonly List&lt;SystemBase&gt; _renderSystems = new List&lt;SystemBase&gt;(); // 实体ID生成器 private int _nextEntityId = 1; // 待添加的实体队列 private readonly Queue&lt;Entity&gt; _pendingEntities = new Queue&lt;Entity&gt;(); // 待移除的实体队列 private readonly Queue&lt;int&gt; _pendingRemovals = new Queue&lt;int&gt;(); // 组件类型到包含该组件的实体的映射 private readonly Dictionary&lt;Type, HashSet&lt;Entity&gt;&gt; _componentEntityMap = new Dictionary&lt;Type, HashSet&lt;Entity&gt;&gt;(); // 世界是否正在运行 private bool _isRunning = false; // 世界名称 private string _worldName; #endregion #region 属性 /// &lt;summary&gt; /// 世界名称 /// &lt;/summary&gt; public string WorldName =&gt; _worldName ?? Name; /// &lt;summary&gt; /// 实体数量 /// &lt;/summary&gt; public int EntityCount =&gt; _entities.Count; /// &lt;summary&gt; /// 系统数量 /// &lt;/summary&gt; public int SystemCount =&gt; _updateSystems.Count + _fixedUpdateSystems.Count + _renderSystems.Count; /// &lt;summary&gt; /// 世界是否正在运行 /// &lt;/summary&gt; public bool IsRunning =&gt; _isRunning; /// &lt;summary&gt; /// 所有实体 /// &lt;/summary&gt; public IEnumerable&lt;Entity&gt; AllEntities =&gt; _entities.Values; #endregion #region Godot 生命周期 public override void _Ready() { base._Ready(); _worldName = Name; // 设置处理模式 ProcessMode = ProcessModeEnum.Always; GD.Print($&#34;[World] 世界 &#39;{WorldName}&#39; 已创建&#34;); } public override void _Process(double delta) { if (!_isRunning) return; float deltaTime = (float)delta; // 处理待添加的实体 ProcessPendingEntities(); // 处理待移除的实体 ProcessPendingRemovals(); // 执行更新系统 ExecuteSystems(_updateSystems, deltaTime); // 刷新所有系统的实体列表 RefreshAllSystems(); } public override void _PhysicsProcess(double delta) { if (!_isRunning) return; // 执行固定更新系统 ExecuteSystems(_fixedUpdateSystems, (float)delta); } public override void _ExitTree() { Stop(); Clear(); base._ExitTree(); } #endregion #region 实体管理 /// &lt;summary&gt; /// 创建实体 /// &lt;/summary&gt; public Entity CreateEntity(string name = null) { var entity = new Entity(_nextEntityId++, this); if (!string.IsNullOrEmpty(name)) { entity.Name = name; } // 添加到待处理队列 _pendingEntities.Enqueue(entity); GD.Print($&#34;[World] 实体已创建: {entity}&#34;); return entity; } /// &lt;summary&gt; /// 获取实体 /// &lt;/summary&gt; public Entity GetEntity(int entityId) { _entities.TryGetValue(entityId, out var entity); return entity; } /// &lt;summary&gt; /// 移除实体 /// &lt;/summary&gt; public void RemoveEntity(Entity entity) { if (entity != null) { _pendingRemovals.Enqueue(entity.Id); } } /// &lt;summary&gt; /// 移除实体 /// &lt;/summary&gt; public bool RemoveEntity(int entityId) { if (_entities.TryGetValue(entityId, out var entity)) { // 从所有系统中移除 RemoveEntityFromSystems(entity); // 从组件映射中移除 RemoveEntityFromComponentMap(entity); // 从字典中移除 _entities.Remove(entityId); // 释放实体 entity.Dispose(); return true; } return false; } /// &lt;summary&gt; /// 处理待添加的实体 /// &lt;/summary&gt; private void ProcessPendingEntities() { while (_pendingEntities.Count &gt; 0) { var entity = _pendingEntities.Dequeue(); _entities[entity.Id] = entity; // 将实体添加到匹配的系统 AddEntityToSystems(entity); } } /// &lt;summary&gt; /// 处理待移除的实体 /// &lt;/summary&gt; private void ProcessPendingRemovals() { while (_pendingRemovals.Count &gt; 0) { var entityId = _pendingRemovals.Dequeue(); RemoveEntity(entityId); } } /// &lt;summary&gt; /// 清除所有实体 /// &lt;/summary&gt; public void ClearEntities() { // 标记所有实体为待移除 foreach (var entityId in _entities.Keys.ToList()) { _pendingRemovals.Enqueue(entityId); } _pendingEntities.Clear(); } #endregion #region 系统管理 /// &lt;summary&gt; /// 添加系统 /// &lt;/summary&gt; public void AddSystem(SystemBase system) { if (system == null) return; // 初始化系统 system.Initialize(this); // 根据执行类型添加到相应列表 switch (system.ExecutionType) { case SystemExecutionType.Update: AddToSystemList(_updateSystems, system); break; case SystemExecutionType.FixedUpdate: AddToSystemList(_fixedUpdateSystems, system); break; case SystemExecutionType.Render: AddToSystemList(_renderSystems, system); break; } // 将现有实体添加到新系统 foreach (var entity in _entities.Values) { if (system.IsEntityValid(entity)) { system.AddEntity(entity); } } system.OnStart(); GD.Print($&#34;[World] 系统已添加: {system.SystemName}&#34;); } /// &lt;summary&gt; /// 将系统添加到列表并按优先级排序 /// &lt;/summary&gt; private void AddToSystemList(List&lt;SystemBase&gt; systemList, SystemBase system) { systemList.Add(system); systemList.Sort((a, b) =&gt; a.Priority.CompareTo(b.Priority)); } /// &lt;summary&gt; /// 移除系统 /// &lt;/summary&gt; public bool RemoveSystem(SystemBase system) { if (system == null) return false; bool removed = false; removed |= _updateSystems.Remove(system); removed |= _fixedUpdateSystems.Remove(system); removed |= _renderSystems.Remove(system); if (removed) { system.OnStop(); system.Dispose(); } return removed; } /// &lt;summary&gt; /// 获取指定类型的系统 /// &lt;/summary&gt; public T GetSystem&lt;T&gt;() where T : SystemBase { foreach (var system in _updateSystems.OfType&lt;T&gt;()) return system; foreach (var system in _fixedUpdateSystems.OfType&lt;T&gt;()) return system; foreach (var system in _renderSystems.OfType&lt;T&gt;()) return system; return null; } /// &lt;summary&gt; /// 执行系统列表 /// &lt;/summary&gt; private void ExecuteSystems(List&lt;SystemBase&gt; systems, float deltaTime) { foreach (var system in systems) { if (system.IsEnabled) { system.Execute(deltaTime); } } } /// &lt;summary&gt; /// 刷新所有系统的实体列表 /// &lt;/summary&gt; private void RefreshAllSystems() { RefreshSystemList(_updateSystems); RefreshSystemList(_fixedUpdateSystems); RefreshSystemList(_renderSystems); } /// &lt;summary&gt; /// 刷新系统列表 /// &lt;/summary&gt; private void RefreshSystemList(List&lt;SystemBase&gt; systems) { foreach (var system in systems) { system.RefreshEntities(); } } #endregion #region 组件管理 /// &lt;summary&gt; /// 组件添加到实体时的回调 /// &lt;/summary&gt; internal void OnComponentAdded(Entity entity, IComponent component) { var componentType = component.GetType(); // 更新组件-实体映射 if (!_componentEntityMap.ContainsKey(componentType)) { _componentEntityMap[componentType] = new HashSet&lt;Entity&gt;(); } _componentEntityMap[componentType].Add(entity); // 检查新组件是否使实体符合某个系统的要求 UpdateEntitySystems(entity); } /// &lt;summary&gt; /// 组件从实体移除时的回调 /// &lt;/summary&gt; internal void OnComponentRemoved(Entity entity, IComponent component) { var componentType = component.GetType(); // 更新组件-实体映射 if (_componentEntityMap.ContainsKey(componentType)) { _componentEntityMap[componentType].Remove(entity); } // 从不再符合要求的系统中移除实体 RemoveEntityFromSystems(entity); } /// &lt;summary&gt; /// 获取拥有指定组件的所有实体 /// &lt;/summary&gt; public IEnumerable&lt;Entity&gt; GetEntitiesWithComponent&lt;T&gt;() where T : class, IComponent { var componentType = typeof(T); if (_componentEntityMap.TryGetValue(componentType, out var entities)) { return entities.Where(e =&gt; e.IsActive); } return Enumerable.Empty&lt;Entity&gt;(); } /// &lt;summary&gt; /// 获取拥有所有指定组件的实体 /// &lt;/summary&gt; public IEnumerable&lt;Entity&gt; GetEntitiesWithComponents(params Type[] componentTypes) { if (componentTypes.Length == 0) return Enumerable.Empty&lt;Entity&gt;(); // 从第一个组件类型的实体开始 if (!_componentEntityMap.TryGetValue(componentTypes[0], out var candidates)) return Enumerable.Empty&lt;Entity&gt;(); // 过滤出拥有所有其他组件的实体 return candidates.Where(entity =&gt; { for (int i = 1; i &lt; componentTypes.Length; i++) { var type = componentTypes[i]; if (!_componentEntityMap.TryGetValue(type, out var entities) || !entities.Contains(entity)) { return false; } } return entity.IsActive; }); } #endregion #region 系统-实体关联 /// &lt;summary&gt; /// 将实体添加到所有匹配的系统 /// &lt;/summary&gt; private void AddEntityToSystems(Entity entity) { AddEntityToSystemList(entity, _updateSystems); AddEntityToSystemList(entity, _fixedUpdateSystems); AddEntityToSystemList(entity, _renderSystems); } /// &lt;summary&gt; /// 将实体添加到系统列表 /// &lt;/summary&gt; private void AddEntityToSystemList(Entity entity, List&lt;SystemBase&gt; systems) { foreach (var system in systems) { if (system.IsEntityValid(entity)) { system.AddEntity(entity); } } } /// &lt;summary&gt; /// 从所有系统中移除实体 /// &lt;/summary&gt; private void RemoveEntityFromSystems(Entity entity) { RemoveEntityFromSystemList(entity, _updateSystems); RemoveEntityFromSystemList(entity, _fixedUpdateSystems); RemoveEntityFromSystemList(entity, _renderSystems); } /// &lt;summary&gt; /// 从系统列表中移除实体 /// &lt;/summary&gt; private void RemoveEntityFromSystemList(Entity entity, List&lt;SystemBase&gt; systems) { foreach (var system in systems) { system.RemoveEntity(entity); } } /// &lt;summary&gt; /// 更新实体所属的系统 /// &lt;/summary&gt; private void UpdateEntitySystems(Entity entity) { UpdateEntitySystemsInList(entity, _updateSystems); UpdateEntitySystemsInList(entity, _fixedUpdateSystems); UpdateEntitySystemsInList(entity, _renderSystems); } /// &lt;summary&gt; /// 在系统列表中更新实体 /// &lt;/summary&gt; private void UpdateEntitySystemsInList(Entity entity, List&lt;SystemBase&gt; systems) { foreach (var system in systems) { bool isValid = system.IsEntityValid(entity); bool isInSystem = system.EntityCount &gt; 0 &amp;&amp; // 这里简化处理，实际应该检查具体是否包含该实体 true; if (isValid &amp;&amp; !isInSystem) { system.AddEntity(entity); } else if (!isValid &amp;&amp; isInSystem) { system.RemoveEntity(entity); } } } #endregion #region 组件映射管理 /// &lt;summary&gt; /// 从组件映射中移除实体 /// &lt;/summary&gt; private void RemoveEntityFromComponentMap(Entity entity) { foreach (var kvp in _componentEntityMap) { kvp.Value.Remove(entity); } } #endregion #region 世界控制 /// &lt;summary&gt; /// 启动世界 /// &lt;/summary&gt; public void Start() { if (_isRunning) return; _isRunning = true; // 启动所有系统 foreach (var system in _updateSystems) system.OnStart(); foreach (var system in _fixedUpdateSystems) system.OnStart(); foreach (var system in _renderSystems) system.OnStart(); GD.Print($&#34;[World] 世界 &#39;{WorldName}&#39; 已启动&#34;); } /// &lt;summary&gt; /// 停止世界 /// &lt;/summary&gt; public void Stop() { if (!_isRunning) return; _isRunning = false; // 停止所有系统 foreach (var system in _updateSystems) system.OnStop(); foreach (var system in _fixedUpdateSystems) system.OnStop(); foreach (var system in _renderSystems) system.OnStop(); GD.Print($&#34;[World] 世界 &#39;{WorldName}&#39; 已停止&#34;); } /// &lt;summary&gt; /// 暂停世界 /// &lt;/summary&gt; public void Pause() { _isRunning = false; } /// &lt;summary&gt; /// 恢复世界 /// &lt;/summary&gt; public void Resume() { _isRunning = true; } /// &lt;summary&gt; /// 清除所有数据 /// &lt;/summary&gt; public void Clear() { Stop(); // 清除实体 ClearEntities(); ProcessPendingRemovals(); // 清除系统 var allSystems = new List&lt;SystemBase&gt;(_updateSystems); allSystems.AddRange(_fixedUpdateSystems); allSystems.AddRange(_renderSystems); foreach (var system in allSystems) { system.Dispose(); } _updateSystems.Clear(); _fixedUpdateSystems.Clear(); _renderSystems.Clear(); // 清除组件映射 _componentEntityMap.Clear(); GD.Print($&#34;[World] 世界 &#39;{WorldName}&#39; 已清除&#34;); } #endregion } } ECS 使用示例：
// 文件路径: Scripts/Examples/ECSExample.cs using Godot; using GameFramework.ECS; namespace GameFramework.Examples { // ============================================ // 组件定义 // ============================================ /// &lt;summary&gt; /// 变换组件 - 实体的位置和旋转 /// &lt;/summary&gt; public class TransformComponent : IComponent { public Entity Entity { get; set; } public bool IsActive { get; private set; } = true; public Vector3 Position { get; set; } = Vector3.Zero; public Vector3 Rotation { get; set; } = Vector3.Zero; public Vector3 Scale { get; set; } = Vector3.One; public void Initialize() { GD.Print($&#34;[TransformComponent] 组件已初始化&#34;); } public void SetActive(bool active) { IsActive = active; } public void Dispose() { // 清理资源 } } /// &lt;summary&gt; /// 移动组件 - 控制实体移动 /// &lt;/summary&gt; public class MovementComponent : IComponent, IUpdatableComponent { public Entity Entity { get; set; } public bool IsActive { get; private set; } = true; public Vector3 Velocity { get; set; } = Vector3.Zero; public float Speed { get; set; } = 5.0f; public Vector3 TargetDirection { get; set; } = Vector3.Forward; public void Initialize() { GD.Print($&#34;[MovementComponent] 组件已初始化&#34;); } public void Update(float deltaTime) { if (!IsActive) return; // 更新速度 Velocity = TargetDirection.Normalized() * Speed; } public void SetActive(bool active) { IsActive = active; } public void Dispose() { Velocity = Vector3.Zero; } } /// &lt;summary&gt; /// 渲染组件 - 实体的视觉表现 /// &lt;/summary&gt; public class RenderComponent : IComponent { public Entity Entity { get; set; } public bool IsActive { get; private set; } = true; public string SpritePath { get; set; } public Color Tint { get; set; } = Colors.White; public bool Visible { get; set; } = true; public void Initialize() { GD.Print($&#34;[RenderComponent] 组件已初始化，Sprite: {SpritePath}&#34;); } public void SetActive(bool active) { IsActive = active; } public void Dispose() { // 清理渲染资源 } } // ============================================ // 系统定义 // ============================================ /// &lt;summary&gt; /// 移动系统 - 处理实体的移动逻辑 /// &lt;/summary&gt; public class MovementSystem : SystemBase&lt;TransformComponent, MovementComponent&gt; { public MovementSystem() : base(SystemExecutionType.Update) { Priority = 10; // 较低的优先级 } public override void Initialize(World world) { _world = world; GD.Print(&#34;[MovementSystem] 系统已初始化&#34;); } public override void Execute(float deltaTime) { // 遍历系统中的所有实体 foreach (var entity in _entities) { var transform = GetC1(entity); var movement = GetC2(entity); // 更新位置 transform.Position += movement.Velocity * deltaTime; // 如果移动了，打印位置 if (movement.Velocity.LengthSquared() &gt; 0.001f) { GD.Print($&#34;[MovementSystem] 实体 {entity.Name} 位置: {transform.Position}&#34;); } } } } /// &lt;summary&gt; /// 渲染系统 - 处理实体的渲染 /// &lt;/summary&gt; public class RenderSystem : SystemBase&lt;TransformComponent, RenderComponent&gt; { public RenderSystem() : base(SystemExecutionType.Render) { Priority = 100; // 渲染系统优先级较低 } public override void Initialize(World world) { _world = world; GD.Print(&#34;[RenderSystem] 系统已初始化&#34;); } public override void Execute(float deltaTime) { foreach (var entity in _entities) { var transform = GetC1(entity); var render = GetC2(entity); if (render.Visible) { // 在这里执行实际的渲染逻辑 // 例如更新Godot节点的位置和显示 } } } } // ============================================ // 使用示例 // ============================================ public class ECSExample : Node { private World _world; public override void _Ready() { // 创建世界 _world = new World(); _world.Name = &#34;GameWorld&#34;; AddChild(_world); // 创建系统 var movementSystem = new MovementSystem(); var renderSystem = new RenderSystem(); // 添加系统到世界 _world.AddSystem(movementSystem); _world.AddSystem(renderSystem); // 创建玩家实体 CreatePlayer(); // 创建敌人实体 CreateEnemy(); // 启动世界 _world.Start(); } /// &lt;summary&gt; /// 创建玩家实体 /// &lt;/summary&gt; private void CreatePlayer() { var player = _world.CreateEntity(&#34;Player&#34;); // 添加变换组件 player.AddComponent(new TransformComponent { Position = new Vector3(0, 0, 0), Scale = Vector3.One }); // 添加移动组件 player.AddComponent(new MovementComponent { Speed = 10.0f, TargetDirection = new Vector3(1, 0, 0) // 向右移动 }); // 添加渲染组件 player.AddComponent(new RenderComponent { SpritePath = &#34;res://Sprites/Player.png&#34;, Tint = Colors.Blue, Visible = true }); GD.Print($&#34;[ECSExample] 玩家实体已创建: {player}&#34;); } /// &lt;summary&gt; /// 创建敌人实体 /// &lt;/summary&gt; private void CreateEnemy() { var enemy = _world.CreateEntity(&#34;Enemy&#34;); // 添加变换组件 enemy.AddComponent(new TransformComponent { Position = new Vector3(10, 0, 0), Scale = new Vector3(1.5f, 1.5f, 1.5f) }); // 添加移动组件 enemy.AddComponent(new MovementComponent { Speed = 3.0f, TargetDirection = new Vector3(-1, 0, 0) // 向左移动 }); // 添加渲染组件 enemy.AddComponent(new RenderComponent { SpritePath = &#34;res://Sprites/Enemy.png&#34;, Tint = Colors.Red, Visible = true }); GD.Print($&#34;[ECSExample] 敌人实体已创建: {enemy}&#34;); } public override void _ExitTree() { _world?.Clear(); } } } 6.3 依赖注入容器 依赖注入（DI）是一种实现控制反转的设计模式，通过容器管理对象的创建和依赖关系。
6.3.1 DI Container 实现 // 文件路径: Scripts/Framework/DI/DependencyContainer.cs using Godot; using System; using System.Collections.Generic; using System.Linq; using System.Reflection; namespace GameFramework.DI { /// &lt;summary&gt; /// 服务生命周期类型 /// &lt;/summary&gt; public enum ServiceLifetime { /// &lt;summary&gt; /// 单例 - 整个应用程序生命周期内只有一个实例 /// &lt;/summary&gt; Singleton, /// &lt;summary&gt; /// 瞬态 - 每次请求都创建新实例 /// &lt;/summary&gt; Transient, /// &lt;summary&gt; /// 作用域 - 在同一作用域内共享实例 /// &lt;/summary&gt; Scoped } /// &lt;summary&gt; /// 服务注册信息 /// &lt;/summary&gt; public class ServiceRegistration { /// &lt;summary&gt; /// 服务类型 /// &lt;/summary&gt; public Type ServiceType { get; set; } /// &lt;summary&gt; /// 实现类型 /// &lt;/summary&gt; public Type ImplementationType { get; set; } /// &lt;summary&gt; /// 服务生命周期 /// &lt;/summary&gt; public ServiceLifetime Lifetime { get; set; } /// &lt;summary&gt; /// 工厂方法 /// &lt;/summary&gt; public Func&lt;DependencyContainer, object&gt; Factory { get; set; } /// &lt;summary&gt; /// 单例实例 /// &lt;/summary&gt; public object SingletonInstance { get; set; } /// &lt;summary&gt; /// 服务名称（可选，用于区分同一类型的多个注册） /// &lt;/summary&gt; public string Name { get; set; } } /// &lt;summary&gt; /// 依赖注入容器 - 管理服务的注册和解析 /// &lt;/summary&gt; public class DependencyContainer { #region 字段 // 服务注册字典 - 按服务类型分组 private readonly Dictionary&lt;Type, List&lt;ServiceRegistration&gt;&gt; _registrations = new Dictionary&lt;Type, List&lt;ServiceRegistration&gt;&gt;(); // 单例实例缓存 private readonly Dictionary&lt;ServiceRegistration, object&gt; _singletonInstances = new Dictionary&lt;ServiceRegistration, object&gt;(); // 作用域实例缓存 private readonly Dictionary&lt;string, Dictionary&lt;ServiceRegistration, object&gt;&gt; _scopedInstances = new Dictionary&lt;string, Dictionary&lt;ServiceRegistration, object&gt;&gt;(); // 当前作用域ID private string _currentScopeId = null; // 父容器（用于作用域嵌套） private readonly DependencyContainer _parentContainer; // 已解析的类型栈（用于检测循环依赖） private readonly HashSet&lt;Type&gt; _resolutionStack = new HashSet&lt;Type&gt;(); #endregion #region 构造函数 public DependencyContainer() { } /// &lt;summary&gt; /// 创建子容器（用于创建作用域） /// &lt;/summary&gt; private DependencyContainer(DependencyContainer parent) { _parentContainer = parent; } #endregion #region 注册服务 /// &lt;summary&gt; /// 注册服务（类型映射） /// &lt;/summary&gt; public ServiceRegistration Register&lt;TService, TImplementation&gt;(ServiceLifetime lifetime = ServiceLifetime.Transient, string name = null) where TService : class where TImplementation : class, TService { return Register(typeof(TService), typeof(TImplementation), lifetime, name); } /// &lt;summary&gt; /// 注册服务（类型映射） /// &lt;/summary&gt; public ServiceRegistration Register(Type serviceType, Type implementationType, ServiceLifetime lifetime = ServiceLifetime.Transient, string name = null) { if (!serviceType.IsAssignableFrom(implementationType) &amp;&amp; !serviceType.IsInterface) { throw new ArgumentException($&#34;类型 {implementationType.Name} 不实现 {serviceType.Name}&#34;); } var registration = new ServiceRegistration { ServiceType = serviceType, ImplementationType = implementationType, Lifetime = lifetime, Name = name }; AddRegistration(serviceType, registration); return registration; } /// &lt;summary&gt; /// 注册服务（实例） /// &lt;/summary&gt; public ServiceRegistration RegisterInstance&lt;TService&gt;(TService instance, string name = null) where TService : class { return RegisterInstance(typeof(TService), instance, name); } /// &lt;summary&gt; /// 注册服务（实例） /// &lt;/summary&gt; public ServiceRegistration RegisterInstance(Type serviceType, object instance, string name = null) { if (instance == null) throw new ArgumentNullException(nameof(instance)); if (!serviceType.IsAssignableFrom(instance.GetType())) { throw new ArgumentException($&#34;实例类型 {instance.GetType().Name} 不兼容 {serviceType.Name}&#34;); } var registration = new ServiceRegistration { ServiceType = serviceType, ImplementationType = instance.GetType(), Lifetime = ServiceLifetime.Singleton, SingletonInstance = instance, Name = name }; AddRegistration(serviceType, registration); return registration; } /// &lt;summary&gt; /// 注册服务（工厂方法） /// &lt;/summary&gt; public ServiceRegistration RegisterFactory&lt;TService&gt;(Func&lt;DependencyContainer, TService&gt; factory, ServiceLifetime lifetime = ServiceLifetime.Transient, string name = null) where TService : class { var registration = new ServiceRegistration { ServiceType = typeof(TService), ImplementationType = typeof(TService), Lifetime = lifetime, Factory = container =&gt; factory(container), Name = name }; AddRegistration(typeof(TService), registration); return registration; } /// &lt;summary&gt; /// 注册自身类型 /// &lt;/summary&gt; public ServiceRegistration RegisterSelf&lt;TImplementation&gt;(ServiceLifetime lifetime = ServiceLifetime.Transient) where TImplementation : class { return Register&lt;TImplementation, TImplementation&gt;(lifetime); } /// &lt;summary&gt; /// 添加注册信息到字典 /// &lt;/summary&gt; private void AddRegistration(Type serviceType, ServiceRegistration registration) { if (!_registrations.ContainsKey(serviceType)) { _registrations[serviceType] = new List&lt;ServiceRegistration&gt;(); } // 如果同名服务已存在，移除旧注册 _registrations[serviceType].RemoveAll(r =&gt; r.Name == registration.Name); _registrations[serviceType].Add(registration); GD.Print($&#34;[DI] 服务已注册: {serviceType.Name} -&gt; {registration.ImplementationType.Name} ({registration.Lifetime})&#34;); } #endregion #region 解析服务 /// &lt;summary&gt; /// 解析服务 /// &lt;/summary&gt; public TService Resolve&lt;TService&gt;(string name = null) where TService : class { return (TService)Resolve(typeof(TService), name); } /// &lt;summary&gt; /// 解析服务 /// &lt;/summary&gt; public object Resolve(Type serviceType, string name = null) { // 检测循环依赖 if (_resolutionStack.Contains(serviceType)) { throw new InvalidOperationException($&#34;检测到循环依赖: {string.Join(&#34; -&gt; &#34;, _resolutionStack)} -&gt; {serviceType.Name}&#34;); } // 检查父容器 if (_parentContainer != null) { try { return _parentContainer.Resolve(serviceType, name); } catch { } } // 查找注册信息 var registration = GetRegistration(serviceType, name); if (registration == null) { // 如果没有注册但类型可以实例化，自动注册为瞬态 if (!serviceType.IsAbstract &amp;&amp; !serviceType.IsInterface) { return CreateInstance(serviceType); } throw new InvalidOperationException($&#34;未找到服务 {serviceType.Name} 的注册信息&#34;); } // 根据生命周期创建或获取实例 _resolutionStack.Add(serviceType); try { return GetOrCreateInstance(registration); } finally { _resolutionStack.Remove(serviceType); } } /// &lt;summary&gt; /// 尝试解析服务 /// &lt;/summary&gt; public bool TryResolve&lt;TService&gt;(out TService service, string name = null) where TService : class { try { service = Resolve&lt;TService&gt;(name); return service != null; } catch { service = null; return false; } } /// &lt;summary&gt; /// 解析所有实现 /// &lt;/summary&gt; public IEnumerable&lt;TService&gt; ResolveAll&lt;TService&gt;() where TService : class { return ResolveAll(typeof(TService)).Cast&lt;TService&gt;(); } /// &lt;summary&gt; /// 解析所有实现 /// &lt;/summary&gt; public IEnumerable&lt;object&gt; ResolveAll(Type serviceType) { if (_registrations.TryGetValue(serviceType, out var registrations)) { foreach (var registration in registrations) { yield return GetOrCreateInstance(registration); } } } /// &lt;summary&gt; /// 获取注册信息 /// &lt;/summary&gt; private ServiceRegistration GetRegistration(Type serviceType, string name) { if (_registrations.TryGetValue(serviceType, out var registrations)) { if (name != null) { return registrations.FirstOrDefault(r =&gt; r.Name == name); } return registrations.FirstOrDefault(); } return null; } /// &lt;summary&gt; /// 获取或创建实例 /// &lt;/summary&gt; private object GetOrCreateInstance(ServiceRegistration registration) { switch (registration.Lifetime) { case ServiceLifetime.Singleton: return GetOrCreateSingleton(registration); case ServiceLifetime.Scoped: return GetOrCreateScoped(registration); case ServiceLifetime.Transient: default: return CreateInstance(registration); } } /// &lt;summary&gt; /// 获取或创建单例 /// &lt;/summary&gt; private object GetOrCreateSingleton(ServiceRegistration registration) { if (registration.SingletonInstance != null) return registration.SingletonInstance; if (_singletonInstances.TryGetValue(registration, out var instance)) return instance; instance = CreateInstance(registration); _singletonInstances[registration] = instance; return instance; } /// &lt;summary&gt; /// 获取或创建作用域实例 /// &lt;/summary&gt; private object GetOrCreateScoped(ServiceRegistration registration) { if (_currentScopeId == null) { throw new InvalidOperationException(&#34;尝试在作用域外解析作用域服务&#34;); } if (!_scopedInstances.TryGetValue(_currentScopeId, out var scope)) { scope = new Dictionary&lt;ServiceRegistration, object&gt;(); _scopedInstances[_currentScopeId] = scope; } if (scope.TryGetValue(registration, out var instance)) return instance; instance = CreateInstance(registration); scope[registration] = instance; return instance; } /// &lt;summary&gt; /// 创建实例 /// &lt;/summary&gt; private object CreateInstance(ServiceRegistration registration) { if (registration.Factory != null) { return registration.Factory(this); } return CreateInstance(registration.ImplementationType); } /// &lt;summary&gt; /// 创建类型实例（自动注入依赖） /// &lt;/summary&gt; private object CreateInstance(Type implementationType) { // 获取构造函数 var constructors = implementationType.GetConstructors(); if (constructors.Length == 0) { throw new InvalidOperationException($&#34;类型 {implementationType.Name} 没有公共构造函数&#34;); } // 选择参数最多的构造函数 var constructor = constructors.OrderByDescending(c =&gt; c.GetParameters().Length).First(); var parameters = constructor.GetParameters(); // 解析参数 var args = new object[parameters.Length]; for (int i = 0; i &lt; parameters.Length; i++) { var param = parameters[i]; var injectAttribute = param.GetCustomAttribute&lt;InjectAttribute&gt;(); string serviceName = injectAttribute?.Name; args[i] = Resolve(param.ParameterType, serviceName); } // 创建实例 var instance = constructor.Invoke(args); // 执行属性注入 InjectProperties(instance); // 执行字段注入 InjectFields(instance); // 调用初始化方法 InvokeInitializeMethods(instance); return instance; } #endregion #region 属性注入 /// &lt;summary&gt; /// 注入属性 /// &lt;/summary&gt; private void InjectProperties(object instance) { var properties = instance.GetType().GetProperties(BindingFlags.Public | BindingFlags.Instance) .Where(p =&gt; p.CanWrite &amp;&amp; p.GetCustomAttribute&lt;InjectAttribute&gt;() != null); foreach (var property in properties) { var injectAttribute = property.GetCustomAttribute&lt;InjectAttribute&gt;(); try { var value = Resolve(property.PropertyType, injectAttribute?.Name); property.SetValue(instance, value); } catch (Exception ex) { if (!injectAttribute?.Optional ?? true) { throw new InvalidOperationException( $&#34;无法注入属性 {property.Name} 到类型 {instance.GetType().Name}&#34;, ex); } } } } #endregion #region 字段注入 /// &lt;summary&gt; /// 注入字段 /// &lt;/summary&gt; private void InjectFields(object instance) { var fields = instance.GetType().GetFields(BindingFlags.Public | BindingFlags.NonPublic | BindingFlags.Instance) .Where(f =&gt; f.GetCustomAttribute&lt;InjectAttribute&gt;() != null); foreach (var field in fields) { var injectAttribute = field.GetCustomAttribute&lt;InjectAttribute&gt;(); try { var value = Resolve(field.FieldType, injectAttribute?.Name); field.SetValue(instance, value); } catch (Exception ex) { if (!injectAttribute?.Optional ?? true) { throw new InvalidOperationException( $&#34;无法注入字段 {field.Name} 到类型 {instance.GetType().Name}&#34;, ex); } } } } #endregion #region 初始化方法 /// &lt;summary&gt; /// 调用标记了[Initialize]的方法 /// &lt;/summary&gt; private void InvokeInitializeMethods(object instance) { var methods = instance.GetType().GetMethods(BindingFlags.Public | BindingFlags.Instance) .Where(m =&gt; m.GetCustomAttribute&lt;InitializeAttribute&gt;() != null); foreach (var method in methods) { // 解析方法参数 var parameters = method.GetParameters(); var args = new object[parameters.Length]; for (int i = 0; i &lt; parameters.Length; i++) { var param = parameters[i]; var injectAttribute = param.GetCustomAttribute&lt;InjectAttribute&gt;(); args[i] = Resolve(param.ParameterType, injectAttribute?.Name); } method.Invoke(instance, args); } } #endregion #region 作用域管理 /// &lt;summary&gt; /// 创建作用域 /// &lt;/summary&gt; public Scope CreateScope() { return new Scope(this); } /// &lt;summary&gt; /// 设置当前作用域 /// &lt;/summary&gt; internal void SetCurrentScope(string scopeId) { _currentScopeId = scopeId; } /// &lt;summary&gt; /// 清除作用域实例 /// &lt;/summary&gt; internal void ClearScope(string scopeId) { if (_scopedInstances.TryGetValue(scopeId, out var instances)) { // 释放可释放的实例 foreach (var instance in instances.Values) { if (instance is IDisposable disposable) { disposable.Dispose(); } } instances.Clear(); _scopedInstances.Remove(scopeId); } } #endregion #region 构建提供者 /// &lt;summary&gt; /// 构建服务提供者 /// &lt;/summary&gt; public IServiceProvider BuildServiceProvider() { return new DIServiceProvider(this); } #endregion #region 清理 /// &lt;summary&gt; /// 释放所有单例实例 /// &lt;/summary&gt; public void Dispose() { // 释放单例 foreach (var instance in _singletonInstances.Values) { if (instance is IDisposable disposable) { disposable.Dispose(); } } _singletonInstances.Clear(); // 释放所有作用域 foreach (var scopeId in _scopedInstances.Keys.ToList()) { ClearScope(scopeId); } _scopedInstances.Clear(); _registrations.Clear(); } #endregion } /// &lt;summary&gt; /// 作用域 - 管理作用域生命周期 /// &lt;/summary&gt; public class Scope : IDisposable { private readonly DependencyContainer _container; private readonly string _scopeId; private bool _disposed = false; internal Scope(DependencyContainer container) { _container = container; _scopeId = Guid.NewGuid().ToString(&#34;N&#34;); _container.SetCurrentScope(_scopeId); } /// &lt;summary&gt; /// 解析服务 /// &lt;/summary&gt; public TService Resolve&lt;TService&gt;(string name = null) where TService : class { if (_disposed) throw new ObjectDisposedException(nameof(Scope)); _container.SetCurrentScope(_scopeId); return _container.Resolve&lt;TService&gt;(name); } /// &lt;summary&gt; /// 释放作用域 /// &lt;/summary&gt; public void Dispose() { if (_disposed) return; _container.ClearScope(_scopeId); _container.SetCurrentScope(null); _disposed = true; } } } 6.3.2 [Inject] 特性 // 文件路径: Scripts/Framework/DI/Attributes.cs using System; namespace GameFramework.DI { /// &lt;summary&gt; /// 注入特性 - 标记需要依赖注入的构造函数、属性、字段或方法参数 /// &lt;/summary&gt; [AttributeUsage(AttributeTargets.Constructor | AttributeTargets.Property | AttributeTargets.Field | AttributeTargets.Parameter, AllowMultiple = false)] public class InjectAttribute : Attribute { /// &lt;summary&gt; /// 服务名称（可选） /// &lt;/summary&gt; public string Name { get; set; } /// &lt;summary&gt; /// 是否可选（如果为true，注入失败不会抛出异常） /// &lt;/summary&gt; public bool Optional { get; set; } public InjectAttribute() { } public InjectAttribute(string name) { Name = name; } } /// &lt;summary&gt; /// 初始化特性 - 标记服务创建后需要调用的初始化方法 /// &lt;/summary&gt; [AttributeUsage(AttributeTargets.Method, AllowMultiple = false)] public class InitializeAttribute : Attribute { /// &lt;summary&gt; /// 初始化优先级（数值越小越早执行） /// &lt;/summary&gt; public int Priority { get; set; } public InitializeAttribute(int priority = 0) { Priority = priority; } } /// &lt;summary&gt; /// 单例特性 - 标记类为单例服务 /// &lt;/summary&gt; [AttributeUsage(AttributeTargets.Class, AllowMultiple = false, Inherited = false)] public class SingletonAttribute : Attribute { /// &lt;summary&gt; /// 服务类型（如果与实现类型不同） /// &lt;/summary&gt; public Type ServiceType { get; set; } public SingletonAttribute() { } public SingletonAttribute(Type serviceType) { ServiceType = serviceType; } } /// &lt;summary&gt; /// 瞬态特性 - 标记类为瞬态服务 /// &lt;/summary&gt; [AttributeUsage(AttributeTargets.Class, AllowMultiple = false, Inherited = false)] public class TransientAttribute : Attribute { /// &lt;summary&gt; /// 服务类型（如果与实现类型不同） /// &lt;/summary&gt; public Type ServiceType { get; set; } public TransientAttribute() { } public TransientAttribute(Type serviceType) { ServiceType = serviceType; } } } 6.3.3 服务注册与获取 // 文件路径: Scripts/Framework/DI/ServiceProvider.cs using System; using System.Collections.Generic; namespace GameFramework.DI { /// &lt;summary&gt; /// 服务提供者接口 /// &lt;/summary&gt; public interface IServiceProvider { /// &lt;summary&gt; /// 获取服务 /// &lt;/summary&gt; T GetService&lt;T&gt;() where T : class; /// &lt;summary&gt; /// 获取服务 /// &lt;/summary&gt; object GetService(Type serviceType); /// &lt;summary&gt; /// 获取命名服务 /// &lt;/summary&gt; T GetService&lt;T&gt;(string name) where T : class; /// &lt;summary&gt; /// 获取所有服务实现 /// &lt;/summary&gt; IEnumerable&lt;T&gt; GetServices&lt;T&gt;() where T : class; } /// &lt;summary&gt; /// DI服务提供者实现 /// &lt;/summary&gt; public class DIServiceProvider : IServiceProvider { private readonly DependencyContainer _container; public DIServiceProvider(DependencyContainer container) { _container = container; } public T GetService&lt;T&gt;() where T : class { return _container.Resolve&lt;T&gt;(); } public object GetService(Type serviceType) { return _container.Resolve(serviceType); } public T GetService&lt;T&gt;(string name) where T : class { return _container.Resolve&lt;T&gt;(name); } public IEnumerable&lt;T&gt; GetServices&lt;T&gt;() where T : class { return _container.ResolveAll&lt;T&gt;(); } } } DI 使用示例：
// 文件路径: Scripts/Examples/DIExample.cs using Godot; using GameFramework.DI; namespace GameFramework.Examples { // ============================================ // 服务接口和实现 // ============================================ /// &lt;summary&gt; /// 游戏配置服务接口 /// &lt;/summary&gt; public interface IGameConfigService { string GameVersion { get; } int MaxPlayers { get; } float DefaultMoveSpeed { get; } } /// &lt;summary&gt; /// 游戏配置服务实现 /// &lt;/summary&gt; public class GameConfigService : IGameConfigService { public string GameVersion { get; } = &#34;1.0.0&#34;; public int MaxPlayers { get; } = 100; public float DefaultMoveSpeed { get; } = 5.0f; } /// &lt;summary&gt; /// 玩家数据服务接口 /// &lt;/summary&gt; public interface IPlayerDataService { void LoadPlayerData(string playerId); void SavePlayerData(string playerId); PlayerData GetPlayerData(string playerId); } /// &lt;summary&gt; /// 玩家数据 /// &lt;/summary&gt; public class PlayerData { public string PlayerId { get; set; } public string PlayerName { get; set; } public int Level { get; set; } public int Experience { get; set; } } /// &lt;summary&gt; /// 玩家数据服务实现 /// &lt;/summary&gt; public class PlayerDataService : IPlayerDataService { // 通过属性注入 [Inject] public IGameConfigService ConfigService { get; set; } private readonly Dictionary&lt;string, PlayerData&gt; _playerDataCache = new Dictionary&lt;string, PlayerData&gt;(); [Initialize] public void Initialize() { GD.Print($&#34;[PlayerDataService] 已初始化，游戏版本: {ConfigService?.GameVersion}&#34;); } public void LoadPlayerData(string playerId) { // 模拟从存储加载 var data = new PlayerData { PlayerId = playerId, PlayerName = $&#34;Player_{playerId}&#34;, Level = 1, Experience = 0 }; _playerDataCache[playerId] = data; GD.Print($&#34;[PlayerDataService] 玩家数据已加载: {playerId}&#34;); } public void SavePlayerData(string playerId) { GD.Print($&#34;[PlayerDataService] 玩家数据已保存: {playerId}&#34;); } public PlayerData GetPlayerData(string playerId) { return _playerDataCache.TryGetValue(playerId, out var data) ? data : null; } } /// &lt;summary&gt; /// 音频服务 /// &lt;/summary&gt; public interface IAudioService { void PlaySound(string soundId); void StopSound(string soundId); void SetVolume(float volume); } public class AudioService : IAudioService { private float _volume = 1.0f; public void PlaySound(string soundId) { GD.Print($&#34;[AudioService] 播放音效: {soundId} (音量: {_volume})&#34;); } public void StopSound(string soundId) { GD.Print($&#34;[AudioService] 停止音效: {soundId}&#34;); } public void SetVolume(float volume) { _volume = Mathf.Clamp(volume, 0, 1); } } // ============================================ // 使用依赖注入的类 // ============================================ /// &lt;summary&gt; /// 玩家管理器 - 使用构造函数注入 /// &lt;/summary&gt; public class PlayerManager { private readonly IPlayerDataService _playerDataService; private readonly IGameConfigService _configService; private readonly IAudioService _audioService; // 构造函数注入 public PlayerManager( IPlayerDataService playerDataService, IGameConfigService configService, IAudioService audioService) { _playerDataService = playerDataService; _configService = configService; _audioService = audioService; GD.Print($&#34;[PlayerManager] 已创建，游戏版本: {_configService.GameVersion}&#34;); } public void CreatePlayer(string playerId) { _playerDataService.LoadPlayerData(playerId); _audioService.PlaySound(&#34;player_join&#34;); GD.Print($&#34;[PlayerManager] 玩家已创建: {playerId}&#34;); } public void RemovePlayer(string playerId) { _playerDataService.SavePlayerData(playerId); _audioService.PlaySound(&#34;player_leave&#34;); GD.Print($&#34;[PlayerManager] 玩家已移除: {playerId}&#34;); } } /// &lt;summary&gt; /// 游戏管理器 - 使用字段注入 /// &lt;/summary&gt; public class GameManager { // 字段注入 [Inject] private IGameConfigService _configService; [Inject] private IAudioService _audioService; [Inject(Optional = true)] private IPlayerDataService _playerDataService; // 可选注入 public void StartGame() { GD.Print($&#34;[GameManager] 游戏启动，版本: {_configService.GameVersion}&#34;); _audioService.PlaySound(&#34;game_start&#34;); } public void EndGame() { GD.Print(&#34;[GameManager] 游戏结束&#34;); _audioService.PlaySound(&#34;game_over&#34;); } } // ============================================ // DI配置和启动 // ============================================ public class DIExample : Node { private DependencyContainer _container; public override void _Ready() { // 创建DI容器 _container = new DependencyContainer(); // 配置服务注册 ConfigureServices(); // 测试依赖注入 TestDependencyInjection(); // 测试作用域 TestScopedServices(); } /// &lt;summary&gt; /// 配置服务 /// &lt;/summary&gt; private void ConfigureServices() { // 注册单例服务 _container.Register&lt;IGameConfigService, GameConfigService&gt;(ServiceLifetime.Singleton); // 注册瞬态服务 _container.Register&lt;IPlayerDataService, PlayerDataService&gt;(ServiceLifetime.Transient); _container.Register&lt;IAudioService, AudioService&gt;(ServiceLifetime.Transient); // 注册工厂方法 _container.RegisterFactory&lt;PlayerManager&gt;(container =&gt; { var playerData = container.Resolve&lt;IPlayerDataService&gt;(); var config = container.Resolve&lt;IGameConfigService&gt;(); var audio = container.Resolve&lt;IAudioService&gt;(); return new PlayerManager(playerData, config, audio); }, ServiceLifetime.Transient); // 注册命名服务 _container.Register&lt;IAudioService, AudioService&gt;(ServiceLifetime.Singleton, &#34;Music&#34;); _container.Register&lt;IAudioService, AudioService&gt;(ServiceLifetime.Singleton, &#34;SFX&#34;); GD.Print(&#34;[DIExample] 服务配置完成&#34;); } /// &lt;summary&gt; /// 测试依赖注入 /// &lt;/summary&gt; private void TestDependencyInjection() { GD.Print(&#34;\n=== 测试依赖注入 ===\n&#34;); // 解析PlayerManager（使用构造函数注入） var playerManager = _container.Resolve&lt;PlayerManager&gt;(); playerManager.CreatePlayer(&#34;player_001&#34;); playerManager.RemovePlayer(&#34;player_001&#34;); // 解析GameManager（使用字段注入） var gameManager = new GameManager(); _container.InjectProperties(gameManager); // 手动执行属性注入 gameManager.StartGame(); gameManager.EndGame(); // 测试命名服务 var musicAudio = _container.Resolve&lt;IAudioService&gt;(&#34;Music&#34;); var sfxAudio = _container.Resolve&lt;IAudioService&gt;(&#34;SFX&#34;); musicAudio.SetVolume(0.5f); sfxAudio.SetVolume(0.8f); GD.Print($&#34;Music和SFX是否是同一实例: {ReferenceEquals(musicAudio, sfxAudio)}&#34;); } /// &lt;summary&gt; /// 测试作用域服务 /// &lt;/summary&gt; private void TestScopedServices() { GD.Print(&#34;\n=== 测试作用域服务 ===\n&#34;); // 注册作用域服务 _container.Register&lt;IPlayerDataService, PlayerDataService&gt;(ServiceLifetime.Scoped); // 创建作用域1 using (var scope1 = _container.CreateScope()) { var playerService1 = scope1.Resolve&lt;IPlayerDataService&gt;(); playerService1.LoadPlayerData(&#34;scope_player_1&#34;); // 在同一个作用域中解析应该得到相同实例 var playerService1Again = scope1.Resolve&lt;IPlayerDataService&gt;(); GD.Print($&#34;同一作用域内实例相同: {ReferenceEquals(playerService1, playerService1Again)}&#34;); } // 创建作用域2 using (var scope2 = _container.CreateScope()) { var playerService2 = scope2.Resolve&lt;IPlayerDataService&gt;(); playerService2.LoadPlayerData(&#34;scope_player_2&#34;); } } public override void _ExitTree() { _container?.Dispose(); } } } 6.4 最佳实践 6.4.1 组件设计原则 单一职责原则：每个组件只负责一个明确的功能 组合优于继承：通过组件组合实现功能，而非深层继承 最小依赖：组件之间应尽量减少直接依赖 数据与逻辑分离：组件存储数据，系统处理逻辑（ECS模式） 6.4.2 ECS 使用建议 实体轻量化：实体应尽可能轻量，避免在实体类中添加过多逻辑 组件数据化：组件应该是纯数据结构，避免包含复杂逻辑 系统专注化：每个系统只处理一种特定类型的逻辑 合理使用查询：避免每帧遍历所有实体，使用组件过滤 6.4.3 依赖注入最佳实践 优先使用接口：服务应该通过接口定义，实现解耦 生命周期管理：正确选择服务的生命周期（Singleton/Scoped/Transient） 避免循环依赖：设计时注意避免服务之间的循环依赖 延迟解析：尽可能在构造函数中注入依赖，而非运行时解析 本章小结 本章详细介绍了 Godot C# 中组件化架构的三种实现方式：
传统组件模式：通过 ComponentBase 基类和生命周期管理实现，适合小规模项目 ECS 架构：提供高性能的实体-组件-系统实现，适合大规模游戏 依赖注入：通过 DI 容器管理服务依赖，提高代码的可测试性和可维护性 选择哪种架构模式取决于项目规模和复杂度：
小型项目：使用传统组件模式即可 中型项目：结合组件模式和 DI 容器 大型项目：采用完整的 ECS 架构配合 DI

事件系统是游戏框架的核心组件之一，它负责管理游戏中各种状态变化的通知机制。一个设计良好的事件系统能够降低模块间的耦合度，提高代码的可维护性和可扩展性。本章将详细介绍如何在 Godot C# 环境中构建一个类型安全、高效且易于使用的事件系统。
1. 设计原理与思路 事件驱动架构是一种以事件为核心的软件架构模式，它改变了传统游戏开发中直接调用的编程范式。
1.1 事件驱动架构的核心概念 事件驱动架构（Event-Driven Architecture，EDA）建立在发布-订阅模式（Publish-Subscribe Pattern）之上。在这种架构中，系统中的组件不直接调用彼此的方法，而是通过事件总线进行间接通信。这种设计带来了以下核心概念：
发布者（Publisher）：生成事件的组件，它不知道谁会接收事件 订阅者（Subscriber）：对特定事件感兴趣的组件，它不知道事件由谁发布 事件总线（Event Bus）：负责事件路由的中心枢纽，解耦发布者和订阅者
┌─────────────────────────────────────────────────────────────────┐ │ 事件驱动架构示意图 │ ├─────────────────────────────────────────────────────────────────┤ │ │ │ ┌───────────┐ ┌───────────┐ ┌───────────┐ │ │ │ 发布者A │────────▶│ │────────▶│ 订阅者X │ │ │ └───────────┘ │ │ └───────────┘ │ │ │ 事件总线 │ │ │ ┌───────────┐ │ │ ┌───────────┐ │ │ │ 发布者B │────────▶│ │────────▶│ 订阅者Y │ │ │ └───────────┘ │ │ └───────────┘ │ │ │ │ │ │ ┌───────────┐ │ │ ┌───────────┐ │ │ │ 发布者C │────────▶│ │────────▶│ 订阅者Z │ │ │ └───────────┘ └───────────┘ └───────────┘ │ │ │ │ 优势： │ │ - 发布者和订阅者完全解耦 │ │ - 可以轻松添加新的订阅者 │ │ - 一个事件可以被多个订阅者接收 │ └─────────────────────────────────────────────────────────────────┘ 1.2 为什么要解耦组件通信 在传统的游戏开发中，组件间的通信往往通过直接引用来实现：
// 传统方式：直接引用 public class PlayerController : Node { private UIManager _uiManager; // 直接依赖 private AchievementSystem _achievementSystem; // 直接依赖 private SaveManager _saveManager; // 直接依赖 public override void _Ready() { _uiManager = GetNode&lt;UIManager&gt;(&#34;/root/UIManager&#34;); _achievementSystem = GetNode&lt;AchievementSystem&gt;(&#34;/root/AchievementSystem&#34;); _saveManager = GetNode&lt;SaveManager&gt;(&#34;/root/SaveManager&#34;); } public void TakeDamage(int damage) { _currentHealth -= damage; // 直接调用UI更新 _uiManager.UpdateHealthBar(_currentHealth); // 直接调用成就检查 _achievementSystem.CheckDamageTaken(damage); // 直接调用存档 _saveManager.AutoSave(); } } 这种方式的问题在于：
耦合度高：PlayerController需要知道所有相关系统的存在 可测试性差：难以单独测试PlayerController，需要构造所有依赖 扩展困难：添加新系统需要修改PlayerController代码 灵活性低：无法在运行时动态添加或移除功能 通过事件系统解耦后，代码变得更加灵活：
// 事件驱动方式：通过事件总线通信 public class PlayerController : EventBusNode { public void TakeDamage(int damage) { _currentHealth -= damage; // 发布事件，不关心谁接收 Publish(new PlayerHealthChangedEvent(this, new PlayerHealthChangeData { CurrentHealth = _currentHealth, Delta = -damage })); } } 1.3 事件总线与直接引用的对比 特性 直接引用 事件总线 耦合度 高（编译时依赖） 低（运行时依赖） 可测试性 差（需要构造所有依赖） 好（可以单独测试） 扩展性 差（需要修改现有代码） 好（添加订阅者即可） 性能 高（直接调用） 中等（委托调用开销） 代码清晰度 直观 需要理解事件流向 调试难度 简单（调用栈清晰） 较难（需要追踪事件） 为什么这样设计？
泛型委托：使用泛型而非object类型，避免装箱拆箱，确保类型安全 生命周期管理：通过EventBusNode自动处理订阅和取消订阅，防止内存泄漏 线程安全：使用lock关键字保护事件字典，支持多线程环境 延迟移除：在事件发布期间取消订阅时延迟处理，避免遍历时的集合修改异常 2. 使用场景分析 2.1 适用场景 模块间通信：当两个模块位于不同的命名空间或层级，且不需要强耦合时
// 场景：成就系统监听多个模块的事件 public class AchievementSystem : Node { public override void _Ready() { // 订阅各种游戏事件 EventBus.Instance.Subscribe&lt;PlayerDeathEvent&gt;(OnPlayerDeath); EventBus.Instance.Subscribe&lt;QuestCompletedEvent&gt;(OnQuestCompleted); EventBus.Instance.Subscribe&lt;InventoryChangedEvent&gt;(OnInventoryChanged); } } UI更新：当游戏状态变化需要更新多个UI元素时
游戏状态变更：关卡开始/结束、暂停/恢复等全局状态变化
跨系统通知：存档、音效、统计等辅助系统需要响应游戏事件
2.2 不适用场景 高频实时通信：如每帧更新的物理计算、动画插值等
// 不推荐：高频事件 public override void _PhysicsProcess(double delta) { // 每帧都发布事件会造成性能问题 EventBus.Instance.Publish(new PositionChangedEvent(this, transform.Position)); } // 推荐：直接调用 public override void _PhysicsProcess(double delta) { // 直接更新位置 _sprite.Position = transform.Position; } 需要同步返回值的场景：事件系统是异步的，无法直接获取返回值
// 不推荐：尝试通过事件获取返回值 public int GetPlayerLevel() { int level = 0; // 事件处理器无法返回数据给发布者 EventBus.Instance.Publish(new QueryPlayerLevelEvent(this, (l) =&gt; level = l)); return level; // 总是0，因为事件是异步处理的 } 2.3 典型案例 成就系统：当玩家完成特定条件时解锁成就 任务系统：任务进度更新时通知UI和奖励系统 UI事件：生命值变化时更新血条、技能冷却时更新图标
成就系统事件流： ┌──────────────┐ ┌──────────────┐ ┌──────────────┐ │ 玩家击杀敌人 │────▶│ 事件总线 │────▶│ 成就系统 │ └──────────────┘ └──────────────┘ └──────────────┘ │ ▼ ┌──────────────┐ │ 统计系统 │ └──────────────┘ │ ▼ ┌──────────────┐ │ UI显示弹窗 │ └──────────────┘ 3. 实现细节讲解 3.1 为什么使用泛型委托 我们使用Action&lt;TEvent&gt;而非Action&lt;object&gt;或Action有两个主要原因：
类型安全：编译时检查事件类型匹配，避免运行时错误
// 使用泛型：编译时类型检查 public void Subscribe&lt;TEvent&gt;(Action&lt;TEvent&gt; handler) where TEvent : IGameEvent { // 如果传入的handler参数类型不匹配，编译器会报错 } // 使用非泛型：运行时可能出错 public void Subscribe(Type eventType, Action&lt;object&gt; handler) { // 运行时可能接收到错误类型的事件 handler.Invoke(wrongTypeEvent); // 运行时异常 } 性能优化：避免装箱拆箱操作
// 值类型事件数据 public struct PlayerHealthChangeData { public int CurrentHealth; public int MaxHealth; public int Delta; } // 使用泛型委托：无装箱 Action&lt;PlayerHealthChangedEvent&gt; handler = (evt) =&gt; { /* ... */ }; // 使用非泛型委托：需要装箱 Action&lt;object&gt; handler = (obj) =&gt; { var evt = (PlayerHealthChangedEvent)obj; // 拆箱 /* ... */ }; 3.2 事件过滤机制设计思路 事件过滤允许订阅者只接收感兴趣的事件子集：
// 实现事件过滤 public class EventFilter&lt;TEvent&gt; where TEvent : IGameEvent { private readonly Func&lt;TEvent, bool&gt; _filter; private readonly Action&lt;TEvent&gt; _handler; public EventFilter(Func&lt;TEvent, bool&gt; filter, Action&lt;TEvent&gt; handler) { _filter = filter; _handler = handler; } public void Handle(TEvent evt) { if (_filter(evt)) { _handler(evt); } } } // 使用示例：只接收特定来源的伤害事件 EventBus.Instance.Subscribe&lt;PlayerHealthChangedEvent&gt;( new EventFilter&lt;PlayerHealthChangedEvent&gt;( evt =&gt; evt.Data.DamageSource?.Name == &#34;BossEnemy&#34;, OnBossDamage ).Handle ); 3.3 内存泄漏防范策略 事件系统最常见的内存泄漏原因是忘记取消订阅：
// 错误示例：内存泄漏 public class UIController : Node { public override void _Ready() { // 订阅事件 EventBus.Instance.Subscribe&lt;PlayerHealthChangedEvent&gt;(OnHealthChanged); } // 忘记在_ExitTree中取消订阅！ // 当UIController被销毁时，事件总线仍然持有对它的引用 } 防范策略：
1. 使用EventBusNode基类：自动处理取消订阅
2. 使用弱引用：
public class WeakEventHandler&lt;TEvent&gt; where TEvent : IGameEvent { private readonly WeakReference _target; private readonly Action&lt;TEvent&gt; _handler; public void Invoke(TEvent evt) { if (_target.IsAlive) { _handler(evt); } else { // 目标已被GC，自动取消订阅 EventBus.Instance.Unsubscribe(evt.GetType(), this); } } } 3. 定期清理：
public void CleanupDeadHandlers() { foreach (var kvp in _handlers.ToList()) { var handlers = kvp.Value.GetInvocationList(); foreach (var handler in handlers) { var target = handler.Target; if (target is Node node &amp;&amp; !IsInstanceValid(node)) { // 节点已被销毁，移除处理器 Delegate.Remove(kvp.Value, handler); } } } } 4. 性能与权衡 4.1 事件分发的时间复杂度 事件系统的主要操作时间复杂度：
操作 时间复杂度 说明 订阅事件 O(1) 字典查找 + 委托组合 取消订阅 O(n) 需要在委托链中查找 发布事件 O(1) 字典查找 + 委托调用 获取订阅者数量 O(n) 遍历委托链 事件发布流程： 1. 根据事件类型查找处理器字典: O(1) _handlers.TryGetValue(typeof(TEvent), out Delegate handlers) 2. 调用处理器委托: O(1) ~ O(n) handlers.Invoke(eventData) // 委托内部遍历所有订阅者 总复杂度：O(1) 平均，O(n) 最坏情况（n为订阅者数量） 4.2 订阅者过多时的性能影响 当订阅者数量过多时，需要考虑：
委托链遍历开销：每个订阅者都会增加调用开销
// 如果有100个订阅者 // 每次发布事件需要遍历100个处理器 // 即使99个处理器什么都不做，遍历开销仍然存在 内存占用：每个订阅都存储一个委托引用
// 假设每个委托引用约32字节 // 1000个订阅者 = 32KB内存 // 10000个订阅者 = 320KB内存 优化策略：
按优先级分组，只在必要时调用低优先级处理器 实现批量发布，一帧内多次相同事件合并处理 定期清理无效的订阅者 4.3 与信号系统的性能对比 方面 C# 事件/委托 Godot 信号 调用开销 较低（直接委托调用） 较高（需要遍历信号连接） 内存占用 较小（每个委托） 较大（信号对象+连接列表） 编辑器支持 无 完整（可视化连接） 动态连接 完全支持 支持但开销大 跨语言 C# only C# + GDScript 类型安全 完全类型安全 需要运行时类型检查 5. 实战指南 5.1 逐步实施步骤 步骤1：定义事件类型
// 为游戏中的主要状态变化定义事件 public class PlayerLevelUpEvent : GameEvent&lt;PlayerLevelUpData&gt; { public PlayerLevelUpEvent(object sender, PlayerLevelUpData data) : base(sender, data) { } } public struct PlayerLevelUpData { public int OldLevel; public int NewLevel; public int ExperienceGained; } 步骤2：创建订阅者基类
// 创建特定功能的订阅者基类 public abstract class AchievementSubscriber : EventBusNode { protected abstract void OnPlayerLevelUp(PlayerLevelUpEvent evt); public override void _Ready() { base._Ready(); Subscribe&lt;PlayerLevelUpEvent&gt;(OnPlayerLevelUp); } } 步骤3：配置全局事件总线
// 在Autoload中初始化 public partial class GameBootstrap : Node { public override void _Ready() { // 确保GlobalEventBus存在 if (GlobalEventBus.Instance == null) { var bus = new GlobalEventBus(); Engine.RegisterSingleton(&#34;GlobalEventBus&#34;, bus); GetTree().Root.AddChild(bus); } } } 步骤4：迁移现有代码
// 原代码 public void LevelUp() { _level++; _uiManager.UpdateLevel(_level); _achievementManager.CheckLevelAchievement(_level); _audioManager.PlaySound(&#34;levelup&#34;); } // 新代码 public void LevelUp() { int oldLevel = _level; _level++; EventBus.Instance.Publish(new PlayerLevelUpEvent(this, new PlayerLevelUpData { OldLevel = oldLevel, NewLevel = _level, ExperienceGained = _currentExp })); } 5.2 常见错误：忘记取消订阅 这是事件系统最常见的错误，会导致内存泄漏和崩溃。
问题代码：
public class TemporaryPopup : Node { public override void _Ready() { // 订阅全局事件 EventBus.Instance.Subscribe&lt;PlayerHealthChangedEvent&gt;(OnHealthChanged); // 5秒后自动关闭 GetTree().CreateTimer(5.0).Timeout += QueueFree; } private void OnHealthChanged(PlayerHealthChangedEvent evt) { // 更新UI } // 忘记在销毁时取消订阅！ } 解决方案：
public class TemporaryPopup : EventBusNode // 使用EventBusNode { public override void _Ready() { base._Ready(); Subscribe&lt;PlayerHealthChangedEvent&gt;(OnHealthChanged); GetTree().CreateTimer(5.0).Timeout += QueueFree; } // EventBusNode会自动处理取消订阅 } // 或者手动处理 public class TemporaryPopup : Node { public override void _Ready() { EventBus.Instance.Subscribe&lt;PlayerHealthChangedEvent&gt;(OnHealthChanged); GetTree().CreateTimer(5.0).Timeout += QueueFree; } public override void _ExitTree() { // 手动取消订阅 EventBus.Instance.Unsubscribe&lt;PlayerHealthChangedEvent&gt;(OnHealthChanged); base._ExitTree(); } } 5.3 测试建议：如何测试事件系统 单元测试事件处理器：
[Test] public void TestHealthChangedEvent() { // Arrange var player = new PlayerController(); var healthUI = new HealthUIComponent(); bool eventReceived = false; EventBus.Instance.Subscribe&lt;PlayerHealthChangedEvent&gt;(evt =&gt; { eventReceived = true; Assert.AreEqual(80, evt.Data.CurrentHealth); }); // Act player.TakeDamage(20); // Assert Assert.IsTrue(eventReceived); } 测试订阅/取消订阅：
[Test] public void TestUnsubscribe() { int callCount = 0; Action&lt;TestEvent&gt; handler = evt =&gt; callCount++; // Subscribe and publish EventBus.Instance.Subscribe&lt;TestEvent&gt;(handler); EventBus.Instance.Publish(new TestEvent(this)); Assert.AreEqual(1, callCount); // Unsubscribe and publish again EventBus.Instance.Unsubscribe&lt;TestEvent&gt;(handler); EventBus.Instance.Publish(new TestEvent(this)); Assert.AreEqual(1, callCount); // Should not increase } 集成测试：
[Test] public void TestEventFlow_PlayerDamageToUI() { // Setup complete scene var player = new PlayerController(); var healthUI = new HealthUI(); AddChild(player); AddChild(healthUI); // Act player.TakeDamage(30); // Wait for event propagation yield return new WaitForSeconds(0.1f); // Assert Assert.AreEqual(&#34;70/100&#34;, healthUI.HealthLabel.Text); } 6. 类型安全的事件总线实现 事件总线（Event Bus）是一种发布-订阅模式（Publish-Subscribe Pattern）的实现，它允许系统中的各个组件通过统一的事件通道进行通信，而无需直接引用彼此。
1.1 EventBus 设计 我们的事件总线设计基于以下核心原则：
类型安全：利用 C# 的泛型机制确保事件类型和处理器类型匹配 生命周期管理：自动处理订阅者的订阅和取消订阅，防止内存泄漏 线程安全：在必要时提供线程安全的事件分发机制 性能优化：避免装箱拆箱，使用强类型委托 首先，我们定义事件接口和基础实现：
// 文件路径: Scripts/Core/Events/IGameEvent.cs using Godot; namespace GameFramework.Core.Events { /// &lt;summary&gt; /// 游戏事件基础接口 /// 所有自定义事件都必须实现此接口 /// &lt;/summary&gt; public interface IGameEvent { /// &lt;summary&gt; /// 事件发送者，用于追踪事件来源 /// &lt;/summary&gt; object Sender { get; } /// &lt;summary&gt; /// 事件创建时间戳 /// &lt;/summary&gt; double Timestamp { get; } /// &lt;summary&gt; /// 是否阻止事件继续传播 /// &lt;/summary&gt; bool IsHandled { get; set; } } /// &lt;summary&gt; /// 带泛型参数的事件接口 /// 用于传递具体的数据类型 /// &lt;/summary&gt; /// &lt;typeparam name=&#34;T&#34;&gt;事件数据类型&lt;/typeparam&gt; public interface IGameEvent&lt;T&gt; : IGameEvent { /// &lt;summary&gt; /// 事件携带的数据 /// &lt;/summary&gt; T Data { get; } } } // 文件路径: Scripts/Core/Events/GameEvent.cs using Godot; namespace GameFramework.Core.Events { /// &lt;summary&gt; /// 游戏事件基础实现 /// 提供通用的事件属性和构造方法 /// &lt;/summary&gt; public abstract class GameEvent : IGameEvent { /// &lt;summary&gt; /// 事件发送者 /// &lt;/summary&gt; public object Sender { get; } /// &lt;summary&gt; /// 事件创建时间戳（使用 Godot 的时间系统） /// &lt;/summary&gt; public double Timestamp { get; } /// &lt;summary&gt; /// 是否已处理（阻止冒泡） /// &lt;/summary&gt; public bool IsHandled { get; set; } /// &lt;summary&gt; /// 构造函数 /// &lt;/summary&gt; /// &lt;param name=&#34;sender&#34;&gt;事件发送者&lt;/param&gt; protected GameEvent(object sender) { Sender = sender; // 使用 Godot 引擎的时间获取当前时间戳 Timestamp = Time.GetTicksMsec() / 1000.0; } } /// &lt;summary&gt; /// 泛型游戏事件实现 /// 可以携带具体的数据类型 /// &lt;/summary&gt; /// &lt;typeparam name=&#34;T&#34;&gt;事件数据类型&lt;/typeparam&gt; public class GameEvent&lt;T&gt; : GameEvent, IGameEvent&lt;T&gt; { /// &lt;summary&gt; /// 事件数据 /// &lt;/summary&gt; public T Data { get; } /// &lt;summary&gt; /// 构造函数 /// &lt;/summary&gt; /// &lt;param name=&#34;sender&#34;&gt;事件发送者&lt;/param&gt; /// &lt;param name=&#34;data&#34;&gt;事件数据&lt;/param&gt; public GameEvent(object sender, T data) : base(sender) { Data = data; } } } 现在实现核心的事件总线类：
// 文件路径: Scripts/Core/Events/EventBus.cs using System; using System.Collections.Generic; using Godot; namespace GameFramework.Core.Events { /// &lt;summary&gt; /// 类型安全的事件总线 /// 管理所有事件的订阅、取消订阅和发布 /// &lt;/summary&gt; public class EventBus { // 单例实例，用于全局事件总线 private static EventBus _instance; public static EventBus Instance =&gt; _instance ??= new EventBus(); // 存储事件处理器，使用字典实现 O(1) 查找 // 键：事件类型，值：该事件类型的处理器委托列表 private readonly Dictionary&lt;Type, Delegate&gt; _handlers = new(); // 用于线程安全的锁对象 private readonly object _lock = new(); // 标记是否正在发布事件，用于延迟移除 private bool _isPublishing; // 待移除的处理器队列（在发布期间使用） private readonly Queue&lt;(Type eventType, Delegate handler)&gt; _pendingRemovals = new(); /// &lt;summary&gt; /// 订阅指定类型的事件 /// &lt;/summary&gt; /// &lt;typeparam name=&#34;TEvent&#34;&gt;事件类型&lt;/typeparam&gt; /// &lt;param name=&#34;handler&#34;&gt;事件处理器&lt;/param&gt; public void Subscribe&lt;TEvent&gt;(Action&lt;TEvent&gt; handler) where TEvent : IGameEvent { // 参数检查 if (handler == null) { GD.PushError(&#34;[EventBus] 处理器不能为空&#34;); return; } lock (_lock) { Type eventType = typeof(TEvent); // 如果字典中已存在该事件类型的处理器，组合新的处理器 if (_handlers.TryGetValue(eventType, out Delegate existingHandler)) { _handlers[eventType] = Delegate.Combine(existingHandler, handler); } else { // 否则添加新的处理器 _handlers[eventType] = handler; } GD.Print($&#34;[EventBus] 已订阅事件: {eventType.Name}&#34;); } } /// &lt;summary&gt; /// 取消订阅指定类型的事件 /// &lt;/summary&gt; /// &lt;typeparam name=&#34;TEvent&#34;&gt;事件类型&lt;/typeparam&gt; /// &lt;param name=&#34;handler&#34;&gt;要移除的事件处理器&lt;/param&gt; public void Unsubscribe&lt;TEvent&gt;(Action&lt;TEvent&gt; handler) where TEvent : IGameEvent { if (handler == null) { return; } lock (_lock) { Type eventType = typeof(TEvent); // 如果正在发布事件，延迟移除 if (_isPublishing) { _pendingRemovals.Enqueue((eventType, handler)); return; } PerformUnsubscribe(eventType, handler); } } /// &lt;summary&gt; /// 执行实际的取消订阅操作 /// &lt;/summary&gt; private void PerformUnsubscribe&lt;TEvent&gt;(Type eventType, Action&lt;TEvent&gt; handler) where TEvent : IGameEvent { if (_handlers.TryGetValue(eventType, out Delegate existingHandler)) { // 移除指定处理器 var newHandler = Delegate.Remove(existingHandler, handler); if (newHandler == null) { // 如果没有处理器了，从字典中移除该事件类型 _handlers.Remove(eventType); } else { _handlers[eventType] = newHandler; } GD.Print($&#34;[EventBus] 已取消订阅事件: {eventType.Name}&#34;); } } /// &lt;summary&gt; /// 发布事件到所有订阅者 /// &lt;/summary&gt; /// &lt;typeparam name=&#34;TEvent&#34;&gt;事件类型&lt;/typeparam&gt; /// &lt;param name=&#34;eventData&#34;&gt;事件数据&lt;/param&gt; public void Publish&lt;TEvent&gt;(TEvent eventData) where TEvent : IGameEvent { if (eventData == null) { GD.PushError(&#34;[EventBus] 事件数据不能为空&#34;); return; } lock (_lock) { Type eventType = typeof(TEvent); // 检查是否有处理器订阅了该事件 if (!_handlers.TryGetValue(eventType, out Delegate handlers)) { return; // 没有订阅者，直接返回 } // 标记正在发布 _isPublishing = true; try { // 转换为具体类型并调用 if (handlers is Action&lt;TEvent&gt; typedHandler) { typedHandler.Invoke(eventData); } else { // 如果不是预期的类型，尝试动态调用 foreach (Delegate handler in handlers.GetInvocationList()) { try { handler.DynamicInvoke(eventData); } catch (Exception ex) { GD.PushError($&#34;[EventBus] 调用处理器时出错: {ex.Message}&#34;); } } } } finally { _isPublishing = false; // 处理延迟移除的订阅 ProcessPendingRemovals(); } } } /// &lt;summary&gt; /// 处理延迟移除的订阅 /// &lt;/summary&gt; private void ProcessPendingRemovals() { while (_pendingRemovals.Count &gt; 0) { var (eventType, handler) = _pendingRemovals.Dequeue(); // 使用反射调用泛型方法 var method = typeof(EventBus).GetMethod(nameof(PerformUnsubscribe), System.Reflection.BindingFlags.NonPublic | System.Reflection.BindingFlags.Instance); var genericMethod = method.MakeGenericMethod(eventType); genericMethod.Invoke(this, new object[] { eventType, handler }); } } /// &lt;summary&gt; /// 清除所有订阅 /// &lt;/summary&gt; public void ClearAllSubscriptions() { lock (_lock) { _handlers.Clear(); _pendingRemovals.Clear(); GD.Print(&#34;[EventBus] 已清除所有订阅&#34;); } } /// &lt;summary&gt; /// 获取指定事件的订阅者数量 /// &lt;/summary&gt; public int GetSubscriberCount&lt;TEvent&gt;() where TEvent : IGameEvent { lock (_lock) { if (_handlers.TryGetValue(typeof(TEvent), out Delegate handler)) { return handler.GetInvocationList().Length; } return 0; } } } } 1.2 强类型事件参数 为了确保类型安全，我们应该为游戏中的不同系统定义具体的事件类型：
// 文件路径: Scripts/Events/GameplayEvents.cs using GameFramework.Core.Events; using Godot; namespace GameFramework.Events { // ==================== 玩家相关事件 ==================== /// &lt;summary&gt; /// 玩家生命值变化数据 /// &lt;/summary&gt; public struct PlayerHealthChangeData { /// &lt;summary&gt; /// 当前生命值 /// &lt;/summary&gt; public int CurrentHealth; /// &lt;summary&gt; /// 最大生命值 /// &lt;/summary&gt; public int MaxHealth; /// &lt;summary&gt; /// 变化量（正数为治疗，负数为伤害） /// &lt;/summary&gt; public int Delta; /// &lt;summary&gt; /// 伤害来源（如果是伤害） /// &lt;/summary&gt; public Node DamageSource; } /// &lt;summary&gt; /// 玩家生命值变化事件 /// &lt;/summary&gt; public class PlayerHealthChangedEvent : GameEvent&lt;PlayerHealthChangeData&gt; { public PlayerHealthChangedEvent(object sender, PlayerHealthChangeData data) : base(sender, data) { } } /// &lt;summary&gt; /// 玩家死亡事件数据 /// &lt;/summary&gt; public struct PlayerDeathData { /// &lt;summary&gt; /// 死亡位置 /// &lt;/summary&gt; public Vector3 DeathPosition; /// &lt;summary&gt; /// 击杀者 /// &lt;/summary&gt; public Node Killer; /// &lt;summary&gt; /// 死亡原因 /// &lt;/summary&gt; public string DeathReason; } /// &lt;summary&gt; /// 玩家死亡事件 /// &lt;/summary&gt; public class PlayerDeathEvent : GameEvent&lt;PlayerDeathData&gt; { public PlayerDeathEvent(object sender, PlayerDeathData data) : base(sender, data) { } } // ==================== 游戏状态事件 ==================== /// &lt;summary&gt; /// 游戏状态变化类型 /// &lt;/summary&gt; public enum GameStateChangeType { Started, // 游戏开始 Paused, // 游戏暂停 Resumed, // 游戏恢复 Ended, // 游戏结束 Restarted // 游戏重新开始 } /// &lt;summary&gt; /// 游戏状态变化数据 /// &lt;/summary&gt; public struct GameStateChangeData { public GameStateChangeType ChangeType; public string PreviousState; public string NewState; } /// &lt;summary&gt; /// 游戏状态变化事件 /// &lt;/summary&gt; public class GameStateChangedEvent : GameEvent&lt;GameStateChangeData&gt; { public GameStateChangedEvent(object sender, GameStateChangeData data) : base(sender, data) { } } // ==================== 物品/库存事件 ==================== /// &lt;summary&gt; /// 物品变化类型 /// &lt;/summary&gt; public enum InventoryChangeType { Added, // 添加物品 Removed, // 移除物品 Used, // 使用物品 Equipped, // 装备物品 Unequipped // 卸下物品 } /// &lt;summary&gt; /// 库存变化数据 /// &lt;/summary&gt; public struct InventoryChangeData { public string ItemId; public int Quantity; public int SlotIndex; public InventoryChangeType ChangeType; } /// &lt;summary&gt; /// 库存变化事件 /// &lt;/summary&gt; public class InventoryChangedEvent : GameEvent&lt;InventoryChangeData&gt; { public InventoryChangedEvent(object sender, InventoryChangeData data) : base(sender, data) { } } // ==================== 任务/成就事件 ==================== /// &lt;summary&gt; /// 任务进度数据 /// &lt;/summary&gt; public struct QuestProgressData { public string QuestId; public string ObjectiveId; public int CurrentProgress; public int TargetProgress; public bool IsCompleted; } /// &lt;summary&gt; /// 任务进度更新事件 /// &lt;/summary&gt; public class QuestProgressEvent : GameEvent&lt;QuestProgressData&gt; { public QuestProgressEvent(object sender, QuestProgressData data) : base(sender, data) { } } /// &lt;summary&gt; /// 成就解锁数据 /// &lt;/summary&gt; public struct AchievementData { public string AchievementId; public string AchievementName; public string Description; public Texture2D Icon; } /// &lt;summary&gt; /// 成就解锁事件 /// &lt;/summary&gt; public class AchievementUnlockedEvent : GameEvent&lt;AchievementData&gt; { public AchievementUnlockedEvent(object sender, AchievementData data) : base(sender, data) { } } } 1.3 订阅者生命周期管理 在 Godot 中，节点的生命周期管理非常重要。我们需要确保当节点被销毁时，自动取消订阅事件，防止内存泄漏。
// 文件路径: Scripts/Core/Events/EventBusNode.cs using Godot; using System; using System.Collections.Generic; namespace GameFramework.Core.Events { /// &lt;summary&gt; /// 提供事件总线功能的节点基类 /// 继承此类的节点会自动管理事件订阅的生命周期 /// &lt;/summary&gt; public abstract partial class EventBusNode : Node { // 存储该节点的所有订阅，用于自动取消订阅 private readonly List&lt;SubscriptionInfo&gt; _subscriptions = new(); /// &lt;summary&gt; /// 订阅事件 /// &lt;/summary&gt; /// &lt;typeparam name=&#34;TEvent&#34;&gt;事件类型&lt;/typeparam&gt; /// &lt;param name=&#34;handler&#34;&gt;处理器&lt;/param&gt; protected void Subscribe&lt;TEvent&gt;(Action&lt;TEvent&gt; handler) where TEvent : IGameEvent { _subscriptions.Add(new SubscriptionInfo { EventType = typeof(TEvent), Handler = handler }); EventBus.Instance.Subscribe(handler); } /// &lt;summary&gt; /// 取消订阅事件 /// &lt;/summary&gt; /// &lt;typeparam name=&#34;TEvent&#34;&gt;事件类型&lt;/typeparam&gt; /// &lt;param name=&#34;handler&#34;&gt;处理器&lt;/param&gt; protected void Unsubscribe&lt;TEvent&gt;(Action&lt;TEvent&gt; handler) where TEvent : IGameEvent { EventBus.Instance.Unsubscribe(handler); // 从本地列表中移除 for (int i = _subscriptions.Count - 1; i &gt;= 0; i--) { if (_subscriptions[i].Handler.Equals(handler)) { _subscriptions.RemoveAt(i); } } } /// &lt;summary&gt; /// 发布事件 /// &lt;/summary&gt; /// &lt;typeparam name=&#34;TEvent&#34;&gt;事件类型&lt;/typeparam&gt; /// &lt;param name=&#34;eventData&#34;&gt;事件数据&lt;/param&gt; protected void Publish&lt;TEvent&gt;(TEvent eventData) where TEvent : IGameEvent { EventBus.Instance.Publish(eventData); } /// &lt;summary&gt; /// 节点退出场景树时自动取消所有订阅 /// &lt;/summary&gt; public override void _ExitTree() { // 自动取消所有订阅 foreach (var subscription in _subscriptions) { // 使用反射调用 Unsubscribe 方法 var method = typeof(EventBus).GetMethod(&#34;Unsubscribe&#34;); var genericMethod = method.MakeGenericMethod(subscription.EventType); genericMethod.Invoke(EventBus.Instance, new object[] { subscription.Handler }); } _subscriptions.Clear(); GD.Print($&#34;[{Name}] 已清理所有事件订阅&#34;); base._ExitTree(); } /// &lt;summary&gt; /// 订阅信息存储结构 /// &lt;/summary&gt; private struct SubscriptionInfo { public Type EventType; public Delegate Handler; } } } 使用示例：
// 文件路径: Scripts/Player/PlayerController.cs using GameFramework.Core.Events; using GameFramework.Events; using Godot; namespace GameFramework.Player { /// &lt;summary&gt; /// 玩家控制器示例 /// 展示如何使用 EventBusNode 基类 /// &lt;/summary&gt; public partial class PlayerController : EventBusNode { [Export] private int _maxHealth = 100; private int _currentHealth; public override void _Ready() { _currentHealth = _maxHealth; // 步骤1：订阅玩家受伤事件 Subscribe&lt;PlayerHealthChangedEvent&gt;(OnHealthChanged); // 步骤2：订阅其他系统的事件 Subscribe&lt;GameStateChangedEvent&gt;(OnGameStateChanged); GD.Print($&#34;[{Name}] 玩家控制器初始化完成&#34;); } /// &lt;summary&gt; /// 处理生命值变化 /// &lt;/summary&gt; private void OnHealthChanged(PlayerHealthChangedEvent evt) { GD.Print($&#34;[{Name}] 生命值变化: {evt.Data.Delta}, 当前: {evt.Data.CurrentHealth}&#34;); // 如果生命值为0，触发死亡事件 if (evt.Data.CurrentHealth &lt;= 0) { Publish(new PlayerDeathEvent(this, new PlayerDeathData { DeathPosition = GlobalPosition, DeathReason = &#34;Health Depleted&#34; })); } } /// &lt;summary&gt; /// 处理游戏状态变化 /// &lt;/summary&gt; private void OnGameStateChanged(GameStateChangedEvent evt) { // 游戏暂停时禁用输入处理 if (evt.Data.ChangeType == GameStateChangeType.Paused) { SetProcessInput(false); } else if (evt.Data.ChangeType == GameStateChangeType.Resumed) { SetProcessInput(true); } } /// &lt;summary&gt; /// 受到伤害 /// &lt;/summary&gt; public void TakeDamage(int damage, Node source) { int previousHealth = _currentHealth; _currentHealth = Mathf.Max(0, _currentHealth - damage); // 发布生命值变化事件 Publish(new PlayerHealthChangedEvent(this, new PlayerHealthChangeData { CurrentHealth = _currentHealth, MaxHealth = _maxHealth, Delta = _currentHealth - previousHealth, DamageSource = source })); } /// &lt;summary&gt; /// 手动取消订阅示例（通常不需要，_ExitTree 会自动处理） /// &lt;/summary&gt; public void StopListeningToHealthChanges() { // 注意：如果手动取消订阅，_ExitTree 中不会再次尝试取消 Unsubscribe&lt;PlayerHealthChangedEvent&gt;(OnHealthChanged); } } } 2. Godot 信号与 C# 事件的选择策略 在 Godot 中，我们有两种主要的事件机制可用：Godot 信号（Signals）和 C# 事件/委托。理解何时使用哪种机制对于构建清晰的游戏架构至关重要。
2.1 何时使用 Godot 信号 Godot 信号适用于以下场景：
编辑器配置：需要在 Godot 编辑器中通过可视化界面连接信号 节点间直接通信：父子节点或兄弟节点之间的直接交互 内置节点事件：响应 Godot 内置节点的事件（如按钮点击、区域进入等） 场景独立事件：事件处理逻辑与特定场景紧密耦合 // 文件路径: Scripts/UI/MainMenuButton.cs using Godot; namespace GameFramework.UI { /// &lt;summary&gt; /// 主菜单按钮示例 /// 展示何时使用 Godot 信号 /// &lt;/summary&gt; public partial class MainMenuButton : Button { [Signal] public delegate void MenuSelectedEventHandler(string menuName); [Export] private string _menuName = &#34;Main&#34;; public override void _Ready() { // 步骤1：连接内置 Pressed 信号 // 这是 Godot 节点的事件，应该使用 Godot 信号 Pressed += OnButtonPressed; } private void OnButtonPressed() { // 步骤2：发射自定义信号 // 这个信号可以在编辑器中连接到其他节点 EmitSignal(SignalName.MenuSelected, _menuName); GD.Print($&#34;[{Name}] 菜单被选中: {_menuName}&#34;); } /// &lt;summary&gt; /// 鼠标悬停效果 /// 使用 Godot 内置信号 /// &lt;/summary&gt; private void OnMouseEntered() { // 修改按钮样式 Modulate = new Color(1.2f, 1.2f, 1.2f); } private void OnMouseExited() { Modulate = Colors.White; } } } // 文件路径: Scripts/Gameplay/TriggerZone.cs using Godot; namespace GameFramework.Gameplay { /// &lt;summary&gt; /// 触发区域示例 /// 展示物理/区域检测相关的 Godot 信号使用 /// &lt;/summary&gt; public partial class TriggerZone : Area3D { [Signal] public delegate void PlayerEnteredEventHandler(Node3D player); [Signal] public delegate void PlayerExitedEventHandler(Node3D player); public override void _Ready() { // 步骤1：连接 Area3D 的内置信号 // 这些是 Godot 引擎提供的物理检测信号 BodyEntered += OnBodyEntered; BodyExited += OnBodyExited; } private void OnBodyEntered(Node body) { // 步骤2：检查是否是玩家 if (body is CharacterBody3D player &amp;&amp; player.IsInGroup(&#34;Player&#34;)) { GD.Print($&#34;[{Name}] 玩家进入触发区域&#34;); // 步骤3：发射自定义信号 // 可以在编辑器中连接此信号到关卡设计相关逻辑 EmitSignal(SignalName.PlayerEntered, player); } } private void OnBodyExited(Node body) { if (body is CharacterBody3D player &amp;&amp; player.IsInGroup(&#34;Player&#34;)) { GD.Print($&#34;[{Name}] 玩家离开触发区域&#34;); EmitSignal(SignalName.PlayerExited, player); } } } } 2.2 何时使用 C# 事件 C# 事件/委托适用于以下场景：
全局/系统级事件：跨多个场景或系统的通信 数据变化通知：需要传递复杂数据的状态变化 解耦系统间通信：不相关的系统需要相互通知 动态订阅：需要在运行时动态添加/移除监听者 类型安全要求高：需要编译时类型检查 // 文件路径: Scripts/Systems/AchievementSystem.cs using GameFramework.Core.Events; using GameFramework.Events; using Godot; using System.Collections.Generic; namespace GameFramework.Systems { /// &lt;summary&gt; /// 成就系统示例 /// 展示何时使用 C# 事件系统 /// &lt;/summary&gt; public partial class AchievementSystem : Node { // 成就数据库 private Dictionary&lt;string, AchievementDefinition&gt; _achievements = new(); // 解锁的成就列表 private HashSet&lt;string&gt; _unlockedAchievements = new(); public override void _Ready() { // 步骤1：订阅全局事件 // 成就系统需要监听多个不相关系统的事件 EventBus.Instance.Subscribe&lt;PlayerDeathEvent&gt;(OnPlayerDeath); EventBus.Instance.Subscribe&lt;QuestProgressEvent&gt;(OnQuestProgress); EventBus.Instance.Subscribe&lt;InventoryChangedEvent&gt;(OnInventoryChanged); InitializeAchievements(); } /// &lt;summary&gt; /// 初始化成就定义 /// &lt;/summary&gt; private void InitializeAchievements() { _achievements[&#34;first_death&#34;] = new AchievementDefinition { Id = &#34;first_death&#34;, Name = &#34;初次阵亡&#34;, Description = &#34;在游戏中第一次死亡&#34;, Condition = (data) =&gt; true }; _achievements[&#34;collector&#34;] = new AchievementDefinition { Id = &#34;collector&#34;, Name = &#34;收藏家&#34;, Description = &#34;收集100个物品&#34;, Condition = (data) =&gt; GetTotalItemsCollected() &gt;= 100 }; // 更多成就定义... } /// &lt;summary&gt; /// 处理玩家死亡事件 /// 这是一个全局事件，来自玩家系统 /// &lt;/summary&gt; private void OnPlayerDeath(PlayerDeathEvent evt) { TryUnlockAchievement(&#34;first_death&#34;); } /// &lt;summary&gt; /// 处理任务进度事件 /// 来自任务系统 /// &lt;/summary&gt; private void OnQuestProgress(QuestProgressEvent evt) { if (evt.Data.IsCompleted) { TryUnlockAchievement($&#34;quest_{evt.Data.QuestId}&#34;); } } /// &lt;summary&gt; /// 处理库存变化事件 /// 来自物品系统 /// &lt;/summary&gt; private void OnInventoryChanged(InventoryChangedEvent evt) { if (evt.Data.ChangeType == InventoryChangeType.Added) { TryUnlockAchievement(&#34;collector&#34;); } } /// &lt;summary&gt; /// 尝试解锁成就 /// &lt;/summary&gt; private void TryUnlockAchievement(string achievementId) { // 检查是否已解锁 if (_unlockedAchievements.Contains(achievementId)) { return; } // 检查是否满足条件 if (_achievements.TryGetValue(achievementId, out var definition)) { if (definition.Condition(null)) { UnlockAchievement(definition); } } } /// &lt;summary&gt; /// 解锁成就并发布事件 /// &lt;/summary&gt; private void UnlockAchievement(AchievementDefinition definition) { _unlockedAchievements.Add(definition.Id); GD.Print($&#34;[AchievementSystem] 解锁成就: {definition.Name}&#34;); // 发布成就解锁事件 // 这将通知 UI 系统显示成就弹窗 // 通知统计系统记录成就 // 通知存档系统保存进度 EventBus.Instance.Publish(new AchievementUnlockedEvent(this, new AchievementData { AchievementId = definition.Id, AchievementName = definition.Name, Description = definition.Description })); } private int GetTotalItemsCollected() =&gt; 0; // 实际实现从存档读取 /// &lt;summary&gt; /// 成就定义结构 /// &lt;/summary&gt; private class AchievementDefinition { public string Id; public string Name; public string Description; public System.Func&lt;object, bool&gt; Condition; } } } 2.3 混合使用策略 在实际项目中，我们需要同时使用两种机制。以下是推荐的分层策略：
// 文件路径: Scripts/Architecture/EventStrategyGuide.md /* 事件使用策略指南： ┌─────────────────────────────────────────────────────────────┐ │ 系统分层架构 │ ├─────────────────────────────────────────────────────────────┤ │ │ │ ┌──────────────┐ │ │ │ UI 层 │ ← 使用 Godot 信号 │ │ │ (按钮、界面) │ - 按钮点击 │ │ └──────┬───────┘ - 界面切换 │ │ │ │ │ ┌──────▼───────┐ │ │ │ 游戏逻辑层 │ ← 使用 C# 事件总线 │ │ │(玩家、敌人) │ - 状态变化 │ │ └──────┬───────┘ - 数据更新 │ │ │ │ │ ┌──────▼───────┐ │ │ │ 系统层 │ ← 混合使用 │ │ │(存档、音效) │ - Godot 信号用于引擎交互 │ │ └──────────────┘ - C# 事件用于跨系统通信 │ │ │ └─────────────────────────────────────────────────────────────┘ 具体规则： 1. 同一节点树内的通信 → Godot 信号 2. 跨系统的全局通信 → C# 事件总线 3. 与 Godot 引擎内置节点交互 → Godot 信号 4. 需要传递复杂数据的事件 → C# 事件 5. 需要在编辑器中配置的事件 → Godot 信号 */ // 文件路径: Scripts/Player/PlayerHealthUI.cs using GameFramework.Core.Events; using GameFramework.Events; using Godot; namespace GameFramework.Player { /// &lt;summary&gt; /// 玩家生命值 UI 组件 /// 展示混合使用策略： /// - 使用 C# 事件监听全局生命值变化 /// - 使用 Godot 信号更新 UI 节点 /// &lt;/summary&gt; public partial class PlayerHealthUI : Control { [Signal] public delegate void HealthCriticalEventHandler(); [Export] private ProgressBar _healthBar; [Export] private Label _healthLabel; [Export] private AnimationPlayer _animationPlayer; // 生命值警告阈值 private const float CriticalHealthThreshold = 0.2f; public override void _Ready() { // 步骤1：订阅全局 C# 事件 // 这是跨系统通信，使用 EventBus EventBus.Instance.Subscribe&lt;PlayerHealthChangedEvent&gt;(OnHealthChanged); // 步骤2：初始化 UI UpdateHealthDisplay(100, 100); } /// &lt;summary&gt; /// 处理生命值变化事件 /// 来自 EventBus 的全局事件 /// &lt;/summary&gt; private void OnHealthChanged(PlayerHealthChangedEvent evt) { var data = evt.Data; // 步骤3：更新 UI UpdateHealthDisplay(data.CurrentHealth, data.MaxHealth); // 步骤4：检查是否处于危险状态 float healthPercent = (float)data.CurrentHealth / data.MaxHealth; if (healthPercent &lt;= CriticalHealthThreshold) { // 步骤5：发射 Godot 信号 // 这个信号可以在编辑器中连接到其他 UI 效果 EmitSignal(SignalName.HealthCritical); // 播放危险状态动画 _animationPlayer?.Play(&#34;health_critical&#34;); } } /// &lt;summary&gt; /// 更新生命值显示 /// &lt;/summary&gt; private void UpdateHealthDisplay(int current, int max) { if (_healthBar != null) { _healthBar.MaxValue = max; _healthBar.Value = current; } if (_healthLabel != null) { _healthLabel.Text = $&#34;{current} / {max}&#34;; } } /// &lt;summary&gt; /// Godot 信号回调示例 /// 可以在编辑器中连接此函数 /// &lt;/summary&gt; public void OnHealthCriticalEffect() { // 屏幕红色闪烁效果 GD.Print(&#34;[{Name}] 触发生命值危急效果&#34;); } public override void _ExitTree() { // 取消订阅 C# 事件 EventBus.Instance.Unsubscribe&lt;PlayerHealthChangedEvent&gt;(OnHealthChanged); base._ExitTree(); } } } 3. 全局事件与局部事件分离 为了构建可维护的大型项目，我们需要明确区分全局事件和局部事件的作用域。
3.1 GlobalEventBus 全局事件总线用于跨场景、跨系统的通信。
// 文件路径: Scripts/Core/Events/GlobalEventBus.cs using Godot; using System; using System.Collections.Generic; namespace GameFramework.Core.Events { /// &lt;summary&gt; /// 全局事件总线 /// 用于跨场景、跨系统的全局事件通信 /// 在游戏整个生命周期内保持存在 /// &lt;/summary&gt; public partial class GlobalEventBus : Node { // 单例实例 private static GlobalEventBus _instance; public static GlobalEventBus Instance { get { if (_instance == null) { GD.PushError(&#34;[GlobalEventBus] 实例尚未初始化。请确保在场景树中添加了 GlobalEventBus 节点&#34;); } return _instance; } } // 内部使用 EventBus 实现 private readonly EventBus _eventBus = new(); // 场景加载完成时重置标记 private bool _shouldResetOnSceneChange = false; public override void _EnterTree() { // 步骤1：确保只有一个实例 if (_instance != null) { GD.PushWarning(&#34;[GlobalEventBus] 存在多个实例，销毁重复实例&#34;); QueueFree(); return; } _instance = this; // 步骤2：设置为持久节点（切换场景时不销毁） ProcessMode = ProcessModeEnum.Always; GD.Print(&#34;[GlobalEventBus] 全局事件总线已初始化&#34;); } /// &lt;summary&gt; /// 订阅全局事件 /// &lt;/summary&gt; public void Subscribe&lt;TEvent&gt;(Action&lt;TEvent&gt; handler) where TEvent : IGameEvent { _eventBus.Subscribe(handler); } /// &lt;summary&gt; /// 取消订阅全局事件 /// &lt;/summary&gt; public void Unsubscribe&lt;TEvent&gt;(Action&lt;TEvent&gt; handler) where TEvent : IGameEvent { _eventBus.Unsubscribe(handler); } /// &lt;summary&gt; /// 发布全局事件 /// &lt;/summary&gt; public void Publish&lt;TEvent&gt;(TEvent eventData) where TEvent : IGameEvent { _eventBus.Publish(eventData); } /// &lt;summary&gt; /// 设置是否在场景切换时重置 /// &lt;/summary&gt; public void SetResetOnSceneChange(bool shouldReset) { _shouldResetOnSceneChange = shouldReset; } /// &lt;summary&gt; /// 清除所有订阅 /// &lt;/summary&gt; public void ClearAllSubscriptions() { _eventBus.ClearAllSubscriptions(); GD.Print(&#34;[GlobalEventBus] 已清除所有订阅&#34;); } public override void _ExitTree() { if (_instance == this) { _instance = null; } base._ExitTree(); } } } 3.2 LocalEventBus 局部事件总线用于场景内部的模块间通信，随场景销毁而清理。
// 文件路径: Scripts/Core/Events/LocalEventBus.cs using Godot; using System; using System.Collections.Generic; namespace GameFramework.Core.Events { /// &lt;summary&gt; /// 局部事件总线 /// 用于单个场景内部的模块间通信 /// 场景切换时自动清理 /// &lt;/summary&gt; public partial class LocalEventBus : Node { // 存储当前场景中所有的局部事件总线 private static readonly Dictionary&lt;string, LocalEventBus&gt; _instances = new(); /// &lt;summary&gt; /// 获取或创建指定作用域的局部事件总线 /// &lt;/summary&gt; /// &lt;param name=&#34;scope&#34;&gt;作用域名称&lt;/param&gt; public static LocalEventBus GetOrCreate(string scope = &#34;default&#34;) { if (_instances.TryGetValue(scope, out var existing)) { return existing; } // 创建新的实例 var instance = new LocalEventBus(scope); // 添加到场景树根节点 var tree = Engine.GetMainLoop() as SceneTree; tree?.Root.CallDeferred(&#34;add_child&#34;, instance); return instance; } // 内部使用 EventBus 实现 private readonly EventBus _eventBus = new(); // 此总线的作用域 public string Scope { get; private set; } // 构造函数 private LocalEventBus(string scope) { Scope = scope; _instances[scope] = this; GD.Print($&#34;[LocalEventBus] 创建新的局部事件总线: {scope}&#34;); } public override void _Ready() { Name = $&#34;LocalEventBus_{Scope}&#34;; } /// &lt;summary&gt; /// 订阅局部事件 /// &lt;/summary&gt; public void Subscribe&lt;TEvent&gt;(Action&lt;TEvent&gt; handler) where TEvent : IGameEvent { _eventBus.Subscribe(handler); } /// &lt;summary&gt; /// 取消订阅局部事件 /// &lt;/summary&gt; public void Unsubscribe&lt;TEvent&gt;(Action&lt;TEvent&gt; handler) where TEvent : IGameEvent { _eventBus.Unsubscribe(handler); } /// &lt;summary&gt; /// 发布局部事件 /// &lt;/summary&gt; public void Publish&lt;TEvent&gt;(TEvent eventData) where TEvent : IGameEvent { _eventBus.Publish(eventData); } /// &lt;summary&gt; /// 获取订阅者数量 /// &lt;/summary&gt; public int GetSubscriberCount&lt;TEvent&gt;() where TEvent : IGameEvent { return _eventBus.GetSubscriberCount&lt;TEvent&gt;(); } public override void _ExitTree() { // 从字典中移除 _instances.Remove(Scope); // 清理所有订阅 _eventBus.ClearAllSubscriptions(); GD.Print($&#34;[LocalEventBus] 销毁局部事件总线: {Scope}&#34;); base._ExitTree(); } } } 3.3 事件作用域管理 为了更好地管理事件作用域，我们提供一个管理器类：
// 文件路径: Scripts/Core/Events/EventScopeManager.cs using Godot; using System.Collections.Generic; namespace GameFramework.Core.Events { /// &lt;summary&gt; /// 事件作用域管理器 /// 提供统一的事件作用域管理接口 /// &lt;/summary&gt; public static class EventScopeManager { // 记录当前激活的作用域 private static readonly HashSet&lt;string&gt; _activeScopes = new(); /// &lt;summary&gt; /// 创建新的局部事件作用域 /// &lt;/summary&gt; /// &lt;param name=&#34;scopeName&#34;&gt;作用域名称&lt;/param&gt; public static LocalEventBus CreateScope(string scopeName) { if (_activeScopes.Contains(scopeName)) { GD.PushWarning($&#34;[EventScopeManager] 作用域 &#39;{scopeName}&#39; 已存在，返回现有实例&#34;); return LocalEventBus.GetOrCreate(scopeName); } _activeScopes.Add(scopeName); return LocalEventBus.GetOrCreate(scopeName); } /// &lt;summary&gt; /// 销毁指定作用域 /// &lt;/summary&gt; public static void DestroyScope(string scopeName) { if (!_activeScopes.Contains(scopeName)) { return; } // 获取并销毁 var bus = LocalEventBus.GetOrCreate(scopeName); bus.QueueFree(); _activeScopes.Remove(scopeName); } /// &lt;summary&gt; /// 销毁所有局部作用域 /// &lt;/summary&gt; public static void DestroyAllScopes() { foreach (var scope in _activeScopes) { var bus = LocalEventBus.GetOrCreate(scope); bus.QueueFree(); } _activeScopes.Clear(); GD.Print(&#34;[EventScopeManager] 已销毁所有局部作用域&#34;); } /// &lt;summary&gt; /// 检查作用域是否存在 /// &lt;/summary&gt; public static bool ScopeExists(string scopeName) { return _activeScopes.Contains(scopeName); } /// &lt;summary&gt; /// 获取所有激活的作用域名称 /// &lt;/summary&gt; public static IEnumerable&lt;string&gt; GetActiveScopes() { return _activeScopes; } } } 使用示例：
// 文件路径: Scripts/Levels/LevelManager.cs using GameFramework.Core.Events; using GameFramework.Events; using Godot; namespace GameFramework.Levels { /// &lt;summary&gt; /// 关卡管理器示例 /// 展示全局事件与局部事件的分离使用 /// &lt;/summary&gt; public partial class LevelManager : Node { // 局部事件总线引用 private LocalEventBus _levelEventBus; [Export] private string _levelName = &#34;Level_1&#34;; public override void _Ready() { // 步骤1：创建局部事件总线 // 此总线只在本关卡内有效 _levelEventBus = EventScopeManager.CreateScope($&#34;Level_{_levelName}&#34;); // 步骤2：订阅局部事件 // 这些事件只在当前关卡内传播 _levelEventBus.Subscribe&lt;PlayerHealthChangedEvent&gt;(OnLocalPlayerHealthChanged); // 步骤3：订阅全局事件 // 这些事件跨所有关卡传播 GlobalEventBus.Instance.Subscribe&lt;GameStateChangedEvent&gt;(OnGlobalGameStateChanged); GD.Print($&#34;[{Name}] 关卡管理器初始化，作用域: Level_{_levelName}&#34;); } /// &lt;summary&gt; /// 局部事件处理器 /// 只响应当前关卡内的事件 /// &lt;/summary&gt; private void OnLocalPlayerHealthChanged(PlayerHealthChangedEvent evt) { // 只在当前关卡内处理生命值变化 // 例如：触发关卡特定的陷阱、检查关卡完成条件等 GD.Print($&#34;[{Name}] 局部处理生命值变化: {evt.Data.CurrentHealth}&#34;); // 发布局部事件通知关卡内的其他系统 _levelEventBus.Publish(new GameStateChangedEvent(this, new GameStateChangeData { ChangeType = GameStateChangeType.Started, NewState = &#34;LevelSpecificState&#34; })); } /// &lt;summary&gt; /// 全局事件处理器 /// 响应跨关卡的全局事件 /// &lt;/summary&gt; private void OnGlobalGameStateChanged(GameStateChangedEvent evt) { // 处理全局游戏状态变化 if (evt.Data.ChangeType == GameStateChangeType.Paused) { // 暂停关卡逻辑 PauseLevel(); } else if (evt.Data.ChangeType == GameStateChangeType.Resumed) { // 恢复关卡逻辑 ResumeLevel(); } } private void PauseLevel() { GetTree().Paused = true; GD.Print($&#34;[{Name}] 关卡已暂停&#34;); } private void ResumeLevel() { GetTree().Paused = false; GD.Print($&#34;[{Name}] 关卡已恢复&#34;); } /// &lt;summary&gt; /// 关卡完成时调用 /// &lt;/summary&gt; public void CompleteLevel() { // 发布全局事件通知游戏管理器 GlobalEventBus.Instance.Publish(new GameStateChangedEvent(this, new GameStateChangeData { ChangeType = GameStateChangeType.Ended, PreviousState = _levelName, NewState = &#34;LevelComplete&#34; })); } public override void _ExitTree() { // 取消订阅全局事件 GlobalEventBus.Instance.Unsubscribe&lt;GameStateChangedEvent&gt;(OnGlobalGameStateChanged); // 局部事件总线会在场景切换时自动销毁 // 不需要手动处理 base._ExitTree(); } } } 最佳实践总结 1. 事件命名规范 // 文件路径: Scripts/Core/Events/NamingConventions.md /* 事件命名规范： 1. 事件类名：使用过去时态，以 &#34;Event&#34; 结尾 - PlayerHealthChangedEvent (玩家生命值已改变) - ItemCollectedEvent (物品已收集) - GameStateChangedEvent (游戏状态已改变) 2. 事件数据类名：描述数据内容，以 &#34;Data&#34; 结尾 - PlayerHealthChangeData - ItemCollectionData - GameStateChangeData 3. 处理器方法名：以 &#34;On&#34; 开头，描述事件 - OnPlayerHealthChanged - OnItemCollected - OnGameStateChanged 4. 事件类型枚举：使用动作描述 - Changed (已改变) - Started (已开始) - Ended (已结束) - Collected (已收集) */ 2. 性能优化建议 // 文件路径: Scripts/Core/Events/PerformanceTips.md /* 性能优化建议： 1. 避免频繁创建事件对象 - 对于高频事件（如每帧更新），考虑使用直接调用而非事件系统 - 重用事件对象或使用结构体作为事件数据 2. 及时取消订阅 - 使用 EventBusNode 基类自动管理生命周期 - 在 _ExitTree 中手动取消订阅 3. 使用对象池 - 对于频繁触发的事件，实现事件对象池 4. 延迟处理 - 对于非紧急事件，考虑在下一帧处理 - 使用 Godot 的 CallDeferred 方法 5. 事件过滤 - 在处理器中尽早检查条件，避免不必要处理 - 使用 IsHandled 属性阻止事件传播 */ 3. 调试和监控 // 文件路径: Scripts/Core/Events/EventDebugger.cs using Godot; using System; using System.Collections.Generic; namespace GameFramework.Core.Events { /// &lt;summary&gt; /// 事件调试器 /// 用于监控事件系统的运行状态 /// &lt;/summary&gt; public partial class EventDebugger : Node { [Export] private bool _enableLogging = true; [Export] private bool _enableWarningOnUnsubscribedEvents = true; // 事件统计 private Dictionary&lt;string, int&gt; _eventPublishCounts = new(); private Dictionary&lt;string, int&gt; _eventHandlerCounts = new(); public override void _Ready() { if (_enableLogging) { GD.Print(&#34;[EventDebugger] 事件调试器已启用&#34;); } } /// &lt;summary&gt; /// 记录事件发布 /// &lt;/summary&gt; public void LogEventPublish(string eventType) { if (!_enableLogging) return; if (!_eventPublishCounts.ContainsKey(eventType)) { _eventPublishCounts[eventType] = 0; } _eventPublishCounts[eventType]++; // 如果某事件发布次数过多，发出警告 if (_enableWarningOnUnsubscribedEvents &amp;&amp; _eventPublishCounts[eventType] &gt; 100) { if (!_eventHandlerCounts.ContainsKey(eventType) || _eventHandlerCounts[eventType] == 0) { GD.PushWarning($&#34;[EventDebugger] 事件 &#39;{eventType}&#39; 已发布 {_eventPublishCounts[eventType]} 次，但没有订阅者&#34;); } } } /// &lt;summary&gt; /// 记录处理器注册 /// &lt;/summary&gt; public void LogHandlerRegistered(string eventType) { if (!_eventHandlerCounts.ContainsKey(eventType)) { _eventHandlerCounts[eventType] = 0; } _eventHandlerCounts[eventType]++; } /// &lt;summary&gt; /// 打印统计信息 /// &lt;/summary&gt; public void PrintStatistics() { GD.Print(&#34;========== 事件系统统计 ==========&#34;); GD.Print(&#34;事件发布统计：&#34;); foreach (var kvp in _eventPublishCounts) { GD.Print($&#34; {kvp.Key}: {kvp.Value} 次&#34;); } GD.Print(&#34;处理器注册统计：&#34;); foreach (var kvp in _eventHandlerCounts) { GD.Print($&#34; {kvp.Key}: {kvp.Value} 个处理器&#34;); } GD.Print(&#34;==================================&#34;); } } } 本章介绍了事件系统的核心设计理念和实现方案。通过类型安全的事件总线、合理的事件作用域分离，以及 Godot 信号与 C# 事件的混合使用策略，我们可以构建出既灵活又易于维护的游戏架构。在实际项目中，请根据具体需求选择合适的通信机制，并始终关注事件订阅的生命周期管理，以避免内存泄漏问题。
